INSERT INTO bed (bed_id, type, status, dept_name, room_id) VALUES ('13', 'Πολύκλινο', 'Διαθέσιμη', 'Pediatrics', '91');
INSERT INTO bed (bed_id, type, status, dept_name, room_id) VALUES ('14', 'Θάλαμος Νοσηλείας', 'Υπό Συντήρηση', 'Oncology', '85');
INSERT INTO bed (bed_id, type, status, dept_name, room_id) VALUES ('15', 'ΜΕΘ', 'Διαθέσιμη', 'Psychiatry', '74');
INSERT INTO bed (bed_id, type, status, dept_name, room_id) VALUES ('16', 'Θάλαμος Νοσηλείας', 'Υπό Συντήρηση', 'Geriatric', '48');
INSERT INTO bed (bed_id, type, status, dept_name, room_id) VALUES ('17', 'Μονόκλινο', 'Υπό Συντήρηση', 'Inpatient Department (IPD)', '40');
INSERT INTO bed (bed_id, type, status, dept_name, room_id) VALUES ('18', 'Μονόκλινο', 'Κατειλημμένη', 'ENT', '21');
INSERT INTO bed (bed_id, type, status, dept_name, room_id) VALUES ('19', 'Πολύκλινο', 'Κατειλημμένη', 'Intensive care unit (ICU)', '11');
INSERT INTO bed (bed_id, type, status, dept_name, room_id) VALUES ('20', 'Πολύκλινο', 'Υπό Συντήρηση', 'Inpatient Department (IPD)', '10');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8ec25fea-dc25-4045-8c95-dcff96c67a68', 'Αυτός λαμβάνουν διολισθήσεις. Δεν ταξινομεί μην μάθε. Διορθώσει επεξεργασία δε να μάθε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ba5c6bb2-8148-4414-9533-6ad2256fe86e', 'Δείξει θυμάμαι είχαμε εκτός τις στραβά του παραδοτέου. Ακούσει θυμάμαι πιο περιβάλλον. Έγραψες αποφάσισε για ποια πάντως επεξεργασία απίστευτα.', '13', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3bbffd82-8f3f-40e2-89ba-bdb9bbd10032', 'Για προσοχή επεξεργασία ωραίο που επί. Γράψει λιγότερο μέχρι μαγικά μια. Λιγότερο κώδικάς πάντως μα τύπου ναι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('67537e0a-4604-49ed-93f2-47e2058aae7b', 'Προγραμματιστές θα ανά χαρακτηριστικό λες δοκιμάσεις ποσοστό τεσσαρών. Ωραίο ειδικά κρατάει που με. Προσθέσει που ως κοιτάζοντας δίνοντας ταξινομεί ύψος.', '137', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7899f86c-2aa2-4206-b750-a19a4373983d', 'Κώδικάς παραγωγικής απαρατήρητο εγώ αγοράζοντας. Την ο να μη ότι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('24dafcfd-0e72-4d6f-9299-ab9edaad378f', 'Να πάντως χώρου ερώτηση ανά κάτι λαμβάνουν. Τρέξει ως διάβασε κανείς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('61da197a-da9a-45d3-bef5-dc2fe2cc0008', 'Θέματα ανώδυνη ώρα όταν εφαρμογή από. Έρθει πολύ απλό ρωτάει μεταφραστής εξακολουθεί απόλαυσε. Ίδιο ακούσει διακοπής. Σημαντικός περίπου ξέχασε εξαρτάται παράγοντες αρπάζεις ανακλύψεις.', '110', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0054d77c-6ea7-4991-840d-09bfa66e2fcd', 'Επιδιορθώσεις μα σας επιστρέφουν τις καταλάθος. Στέλνοντάς ανταγωνιστής σου. Έτοιμος μέρος προσπαθήσεις παραπάνω.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a71e6217-7328-4643-a692-6c5823dac23b', 'Ανεπιθύμητη κόψεις με δεν. Μέρος υόρκη λαμβάνουν όταν μηχανής σας παίρνουν. Μου έξι τελειώσει αναφορά αντιλήφθηκαν επί να.', '83', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('aa45ec11-75f1-439c-a9d6-5b40331ef53d', 'Δημιουργείς σπίτι φακέλους εγώ να δεν νέων ρουτίνα. Ένας γραμμή περίπου εσωτερικών.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('830e998c-2533-4e5a-89d8-7a0765344841', 'Κοιτάζοντας προκύπτουν διοικητικό εργάστηκε. Ορίστε σίγουρος εργάστηκε δούλευε πρώτης επενδυτής μέσης.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0bb2903d-876d-4d7c-b709-0d7d1d693dbf', 'Κώδικάς τύπους πρώτο πήρε εργασίας προσπαθούν. Έρθει μηχανής παράδειγμα ανταγωνιστής μεταγλωτιστής κάτι δουλεύει. Των τους έτσι ο.', '96', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d66b2835-52f8-46b0-be9a-0c663d134a76', 'Ανακλύψεις έλεγχος και συνηθίζουν. Χρόνου εγώ στο δυστυχώς ύψος ζητήσεις. Μην νέα από εκτός ημέρα θέματα πάρεις εξακολουθεί.', '72', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b1d1e455-3239-4677-8170-c1f3c1ce16af', 'Γραμμή μπορούσες νέο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9b4041ee-343c-43f6-ae1c-d58d429c3de6', 'Τρέξει επί νέου από έχω διαπιστώνεις φαινόμενο. Κανόνα λοιπόν εικόνες επιστρέφουν μεταγλωτιστής.', '54', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('da3e449c-34f0-48ab-8e0c-121433a7deeb', 'Παίξουν και δύο κύκλο. Έρθει δίνοντας παίρνει μετράει αυτήν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f08c66b9-0189-418d-b590-368411061be2', 'Ήδη συνέχεια μη μάτσο τα έστειλε απαράδεκτη. Έχω εγώ πόρτες τη εργοστασίου σημαντικό το.', '136', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6bf47faa-ebe3-4ca9-ad06-fde60dd23abe', 'Συγκεντρωμένοι μεταγλωτιστής σαν τον υπηρεσία μέσης δεν δουλεύει. Στο κάτι ο.', '55', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('48e54b45-2c2c-43fe-9781-0ed286d0fbe0', 'Δημιουργήσεις απαρατήρητο οι συγχωνευτεί μα σκεφτείς συγχωνευτεί. Κώδικα ώρα σημαντικός δύο φακέλους παίξουν.', '8', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('eb75be0a-6087-46e2-adcb-0d3b3474636b', 'Δε γειτονιάς έστελνε πήρε συνεντεύξεις έτσι πρώτης.', '11', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3c16819a-13db-4ef9-b62f-e2000331b105', 'Τι κάτι κι υπηρεσία οι εργάστηκε της στις. Ποσοστό πλέον μια κανένας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c86ecd4c-3851-459d-8cd4-a32ca45093ad', 'Λίγο χώρου και κόψεις κανένας κώδικάς στο γράψει. Βρίσκονται ήδη καλύτερο των τοπικές.', '46', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9c2c6292-fe4e-40ba-95b1-a5b5e463dcac', 'Κλπ σε δυστυχής χαμηλός ημέρα. Εργαζόμενων αρπάζεις προκαλείς μεταγλωτιστής έχω.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('73460955-4752-49f2-a494-1f1e2b8bee2d', 'Τη γραμμής δε τον μέχρι πρόσληψη. Χαρτιού όχι κάτι προσπαθήσεις μάτσο μάτσο κανόνα την. Έξι σε αποδείξεις ήδη προκαλείς αλγόριθμου.', '51', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('67c2aee7-4212-4eb9-b629-5d6876deef91', 'Άρθρων ημέρα θέμα μέχρι. Φακέλους ιδιαίτερα ποια άτομο έτσι κάνε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2c3de429-6079-4cb3-a81a-f471f6051404', 'Προσπαθήσεις θέματα γιαυτό. Ξέχασε γέλασαν πάρεις ημέρα μέρος δίνοντας απίστευτα.', '148', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1ee4b657-f406-4a81-ab7b-6c884d5fc724', 'Εδώ πηγαίου συγχρόνως. Ερώτηση οι άρα ρωτάει ρωτήσει μετράει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('92a58af0-c16f-4947-9a74-57e273ed3a03', 'Κάνε πόρτες τους των μια. Συνέχεια έξι διαπιστώνεις γραμμή επί έξι έχω δυστυχής. Εντολές τελειώσει ελέγχου γνωρίζουμε πετάνε δε πιο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('145c38d6-a023-4463-99ef-c7c2e4b00ed7', 'Μην στο χρησιμοποίησέ ας περιμένουν όχι. Μα για παραδώσεις εφαρμογή κοιτάζοντας ίδιο εκθέσεις.', '124', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1f15f204-937c-4f53-82a5-fe1151002215', 'Δυστυχής ελέγχου γνωστή απαραίτητο. Έτσι διάσημα μας νέο γραμμής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f039c6cd-d289-4969-9627-9292ac0aa12e', 'Μέχρι γραμμής ότι εκθέσεις περισσότερες κρατήσουν επιχείριση. Συνεντεύξεις ας απλό σου ευκολότερο τους σημαντικός. Έστελνε ταξινομεί συνεχώς μιας χρησιμοποιούσες του.', '125', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1f205a95-0ba7-4060-830f-4ff86fdecedf', 'Χρησιμοποιούνταν μια διευθυντές αν ο εταιρείες υόρκη αρέσει. Λες προκύπτουν επί διάσημα διάβασε.', '111', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('36fef153-9a9e-4e15-9340-de9bbee5b859', 'Ήδη δοκιμάσεις εργασίας εταιρείες γραμμές. Μας πάντα διαφήμιση αυτήν τις πλέον περιμένουν ανώδυνη. Προϊόντα στα διαφήμιση επιδιόρθωση νέου.', '22', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d4d83e01-899b-477f-a771-b5fa34174b48', 'Ο κι εδώ όχι ακούσει τον χρησιμοποίησέ. Αποδείξεις τεσσαρών κώδικα άλγεβρα καλύτερο ας μιας ότι. Απίστευτα τι εδώ μια. Σημαντικό ανεπιθύμητη εργαζόμενοι εφαμοργής ρουτίνα.', '93', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e53559b9-bfb9-4925-b7d3-9941a643d228', 'Αθόρυβες περιμένουν βάζοντας αθόρυβες προσεκτικά ορίστε για. Ίδιο μιας πάντα όχι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4a48160c-1c3f-4106-bd3e-736e1fd85c2e', 'Πάντα μη κρατήσουν εκείνου γράψει λες συγχρόνως. Μάθε υόρκη μέσης στραβά ανταγωνιστής. Περιεχόμενα ιδιαίτερα δε αν διαχειριστής συνηθίζουν.', '81', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('54f0e6a9-9fdf-45fa-99aa-de9ecdc37346', 'Στραβά κι αφήσεις. Χρησιμοποιούνταν νόμιζες εκτελείται πάντως πως με του. Ροή ατόμου νέου ανεπιθύμητη.', '100', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5f48d3c3-e09f-4bae-9b7a-de1f74bec516', 'Εκτός κάνε βρίσκονται εδώ ήδη ένας. Όταν να χρησιμοποιώντας υόρκη τις ως δε άρα. Τι μαγικά δημιουργια.', '44', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2a30fa6c-1290-46cd-b719-f82eb32c4e45', 'Διακοπή δημιουργείς λέει σε προϊόντα δεν τις όταν. Θα δημιουργια θέλεις μάτσο.', '134', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c76d4ebf-55fc-4b8a-b3e0-f587724e3db8', 'Προϊόντα περισσότερη μην κοιτάζοντας ήδη εκτελέσει διαφήμιση. Ωραίο επιχείριση ως μάθε μάθε.', '89', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0a1d904a-17d2-4280-a85c-3b7acc890a4a', 'Εκτός χαρακτηριστικό ερωτήσεις διαπιστώνεις ο οι μιας. Σταματάς σου άλγεβρα εκθέσεις την αν. Πάρεις εικόνες απλό χρόνου ανεπιθύμητη. Καλύτερο απίστευτα μάλλον μη.', '139', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('58253351-cfb2-40a3-bae4-cd23efb5eeb8', 'Σου πολύ ναι ο γέλασαν λέει. Προβληματική συνηθίζουν κοιτάζοντας ταξινομεί κλπ έτοιμος έχω. Χρόνου που πάρα εγώ.', '1', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6bab4838-9fa2-4cf1-91f3-2f5559a73f94', 'Εκτελείται στήλες ας στέλνοντάς άρα απλό θυμάμαι. Πρόσληψη περιεχόμενα γέλασαν απόλαυσε. Διασφαλίζεται μέχρι πόρτες κειμένων θέλεις δουλεύει την.', '135', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9df3ea38-cb6f-480f-a0ff-421f3bed6e30', 'Κρατήσουν παραδοτέου βιβλίο. Όταν αποστηθίσει διαπιστώνεις πάντα αυτός. Τρέξει ως χρόνου νέου διαφήμιση περίπου περιεχόμενα.', '133', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3a341232-726f-494d-aac0-4520aa30adf1', 'Αντιλήφθηκαν έτσι δούλευε εδώ εφαρμογής. Δεν πρώτο ήδη όταν εταιρείες. Κάτι δύο εκτός βουτήξουν προσπαθήσεις αν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1cdfda39-fa5e-4831-a27f-a8d15d2b2561', 'Συνηθίζουν θα συνάδελφος με δύο πάντως καταλάθος. Εγώ κανόνα στις βάζοντας ως.', '94', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d962416d-65bc-4d8e-8139-ec54bdbea82a', 'Στη χαρακτηριστικών τελειώσει ιδιαίτερα την. Λετπά διαπιστώνεις πεδία απαραίτητο στέλνοντάς χρησιμοποιώντας βγήκε γραμμής. Φράση υόρκη και διαπιστώνεις συγκεντρωμένοι ως πλέον σημεία.', '74', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a83973a9-f43e-40d7-908d-20b394f98bf0', 'Πεδία εγώ μπορούσες γιαυτό προγραμματιστές προκύπτουν. Γεύματος τεσσαρών χαρτιού πάντως μέχρι ποσοστό αναφέρονται. Λαμβάνουν τρόποι ευκολότερο πάρεις χάος άπειρα.', '39', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('88747092-f8e9-4fc4-aeeb-47b432d14da0', 'Πάντως μα έτσι τρόπο. Το λαμβάνουν ποια γειτονιάς. Στο διαχειριστής πάντα εργασίας πολύ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('465cacb1-3d46-4b5e-ab20-d51abc7b1785', 'Ελέγχου τη απίστευτα μια πλέον μέχρι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('85a61fda-7eac-4532-b14c-ee9ddbce79b7', 'Οι έλεγχος ανά εκτελέσει αποστηθίσει. Πεδία παίρνει άρα του πλέον εργαλείων έστελνε.', '27', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('605202c7-f357-4ebb-80ac-73fe7fc46c1e', 'Μεταφραστής της πλέον. Σε τι είχαμε τη αποκλειστικούς αυτήν όσο σας. Διάσημα κοιτάζοντας πες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2c1241ef-dc0e-4b79-b425-8bd5ec28de4f', 'Υπηρεσία ερωτήσεις επιδιορθώσεις ροή επί. Πρώτοι μέσης πάντως μετράει. Μαγικά λέει σπίτι δεν διοικητικό. Συνεντεύξεις διαφήμιση επί πήρε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('862e4b80-c2ac-43bc-891d-ef964ad5e0a6', 'Των μέχρι πάντα είχαμε. Γραμμή χαρτιού ίδιο τα. Σπίτι μετράει ανά περιβάλλον μετράει να πολύ λετπά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cf963925-ecda-4ffa-96e4-1ab86cf23b5f', 'Τρόποι επεξεργασία κανείς συνέχεια ναι σε απομόνωση. Σημαντικό νέων εκτελέσεις γεγονός της προσοχή. Αναγκάζονται στο ανά έχω του.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2c25e4e8-ed79-4044-86ab-602b06a96c04', 'Περιβάλλοντος σχεδιαστής υπηρεσία τρέξει κάτι. Σας αφήσεις που ξέχασε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0604292c-aeff-46a9-9d89-0abd1f963f25', 'Τύπου προσοχή απαράδεκτη μιας σημεία ερωτήσεις κάτι. Μάλλον μαγικά αυτός. Συγγραφείς κώδικάς εξακολουθεί επεξεργασία απλό εδώ με.', '124', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('214c7ada-179a-4c6f-8c21-6f8ed030f513', 'Πάντως διοικητικό ναι απομόνωση στα. Χαρτιού μπουν κι μέσης μιας κάτι.', '134', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4803e9e1-5328-474a-bbf2-42e226a831f3', 'Απαρατήρητο τις αναγκάζονται εκείνου απομόνωση κόλπα αντιλήφθηκαν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fcff3f7a-0e77-481a-8cc9-5596f8b09c7f', 'Πετάξαμε από στραβά μη οι. Περίπου ταξινομεί άρθρων μιας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('aea700f4-b00d-4f7e-b01a-72447f8307e8', 'Πολύ διορθώσει ποσοστό απαραίτητο. Τα εργαζόμενων να ελέγχου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('446062c3-6cc2-4606-8b8a-e0147255edfb', 'Στη χαρτιού για εργασίας ερωτήσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fe98cb0d-70f7-4d63-8390-43169bfe6fe3', 'Ας εργασίας όσο πιο απόλαυσε του αποστηθίσει της. Δημιουργείς ήδη τι νέο ατόμου ήδη. Τι όσο πιο μην.', '36', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c8129083-e658-4771-9d42-fb49bf9c7dd3', 'Πακέτων ρουτίνα γνωρίζουμε γραμμές τη κάτι προκαλείς δοκιμάσεις. Μη εργοστασίου γνωστή.', '102', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2a4ebaee-796a-4be7-abb0-4c23d994ced3', 'Γεύματος αποκλειστικούς ακούσει απόλαυσε χρειάζονται. Ποια πρόσληψη για στο απαράδεκτη εξαρτάται απαραίτητο μας. Μπορούσες ποια έξι τεκμηριώνει.', '103', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('db385f52-3912-43cc-a998-e6d32bd9a1e8', 'Τι εξαρτάται τοπικές υόρκη επεξεργασία παίρνει μαγικά. Μια δύο αναφορά πάντως πρώτοι χειρότερα έτσι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e837e8ba-c26e-4ac7-9df5-eb03af919b29', 'Έχω παίρνει γράψει αποθηκευτικού σπίτι οι. Προσλάμβανες διακοπή εφαρμογής ότι αντιλήφθηκαν λες. Δυστυχής και λιγότερο ακούσει έλεγχος την σταματάς. Ιδιαίτερα συνεντεύξεις σωστά μέχρι.', '102', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7bd763fa-45ec-4f67-b821-20f058adefc4', 'Αν γράψει νόμιζες μιας συνάδελφος για. Ποσοστό τεκμηριώνει πιο τις γεύματος εξαρτάται διαφήμιση. Όσο εφαρμογής τι περιμένουν είχαμε έτσι κύκλο χαρακτηριστικό. Αγοράζοντας θέλεις σας που.', '104', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f32dfd38-833b-4d16-bca9-4d9fc760adb1', 'Πάντα σπίτι ποια αρέσει τελειώσει επιστρέφουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('82971bf8-50b5-4602-945c-51d08548f5e3', 'Συνεντεύξεις σου χρειάζονται μια. Ας εφαρμογή ότι. Τρόπο εταιρείες επενδυτής πολύ εταιρείες γραμμής ίδιο. Ίδιο ήδη έτοιμος των πρώτης μέγιστη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('35565fad-67d5-4b9f-a594-7cfacbf10db6', 'Σου πάντα κόλπα δυστυχής έτσι συνάδελφος της διοικητικό. Οι να πάντα λιγότερο. Οι πες απόλαυσε περιβάλλον έχω ιδιαίτερα πάντα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('27c414ee-f296-413c-adc7-474db8fd3252', 'Δε ποια αγοράζοντας έτοιμος λοιπόν χρονοδιαγράμματος. Εκτελέσει ώρα δεν πιο σημαντικό βάζοντας παράδειγμα χαρακτηριστικό. Βάζοντας προσπαθούν ατόμου περίπου περισσότερη έξι τα ροή.', '100', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('81c616e1-2741-476b-b960-1217c116d237', 'Σωστά τεσσαρών δυστυχώς διακοπή κανόνα προσθέσει εκθέσεις για. Στραβά πόρτες κρατάει ερώτηση. Χώρου διάβασε στις. Εκτελέσεις συνάδελφος κρατάει δημιουργήσεις σας.', '46', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7629f43d-b668-40e5-acd8-bd361afe50c1', 'Επιχείριση γειτονιάς έλεγχος όταν. Μεταφραστής βασανίζουν διάσημα εκτελέσεις και σαν.', '124', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bdf95c71-3401-4b5e-9f6b-586599ad1ae3', 'Πόρτες μη προκύπτουν άτομο που την εφαρμογής. Ανεπιθύμητη κρατήσουν εκτός πάντως εξοργιστικά. Κοιτάζοντας κώδικάς ξέχασε κι γειτονιάς.', '96', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('016d0c87-79e7-4ac1-93db-44f901207a3e', 'Απλό υόρκη υποψήφιο νέο διοικητικό από τύπους παίρνει. Συνεχώς διακόψουμε γνωστή.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8b07c4a3-ed55-4095-a83b-d46c999ce364', 'Εγώ δουλεύει παραπάνω αναφορά. Γραμμές χαρακτηριστικό σας λες. Ήδη θα επιστρέφουν πολύ που.', '68', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c1c4f067-0f1d-4b49-b4e8-516d93381853', 'Τους υόρκη πάντως ώρα νέου κι. Υποψήφιο πάντα έστελνε μια.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('af245645-f717-4a71-8a70-f7d77239e20a', 'Μηχανής εκτελέσει αποφάσισε την συγκεντρωμένοι τύπους δύο. Εκτός πρόσληψη διακοπής επί. Βιαστικά κρατήσουν γεύματος ήδη διαχειριστής αγοράζοντας που.', '37', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d672c4b7-a198-4875-82b2-5ccf14ebf328', 'Ένας τα ταξινομεί λίγο ακούσει διοικητικό. Στραβά έστελνε αποθηκευτικού. Ευκολότερο κώδικα βαθμό καλύτερο αλγόριθμου συγχωνευτεί πες.', '34', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d7524c23-278e-4b7f-ad4a-33b528519dc5', 'Ρωτήσει ήδη προσεκτικά. Άρθρων κάτι χαμηλός αναγκάζονται επιδιορθώσεις βιαστικά τα. Εγώ βασανίζουν το ξέχασε τη τύπους μέχρι χειρότερα.', '81', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('eaf2f467-5391-44a0-a33d-23eba8327080', 'Μεταγλωτιστής το κάτι στη ποια προσπαθήσεις εξαρτάται. Πως αναγκάζονται μαγικά είχαμε απλό εξοργιστικά να αγοράζοντας.', '115', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9a5de6ac-f053-4438-b54e-a2d9144eb207', 'Νέου εκτός τις κώδικάς άπειρα. Περισσότερη ευκολότερο από σαν εγώ τις. Συνέχεια δείξει ειδικά έτσι.', '80', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1e78c892-c358-4717-9b7b-5cde5b1a511a', 'Πάντα σπίτι μάλλον. Πολύ συγγραφής πρόσληψη εκείνου στις θέματα. Ξέχασε ότι παραδώσεις μιας προβληματική κανόνα των.', '32', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('740c90cb-39a1-4fd9-b9d4-00d76ccbd528', 'Γέλασαν ρωτάει διορθώσει ανώδυνη. Εξοργιστικά τα παράδειγμα έξι σαν. Χαρτιού προκύπτουν χαρακτηριστικό στραβά. Μπορούσες το χαρακτηριστικών εγώ.', '142', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8ef99a1f-b9e6-44c9-b323-391f71c14791', 'Επιδιορθώσεις των μετράει γραμμής επεξεργασία. Προκαλείς δωροδοκηθούν δυστυχής προκαλείς ελέγχου.', '98', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4f9ca89f-b12e-4998-9179-93f2ccc35299', 'Κάτι μιας διολισθήσεις λετπά της περίπου του. Στέλνοντάς δυστυχώς από ξέχασε απαραίτητο. Τις κάτι χαμηλός τους θέμα.', '99', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f6cad903-d4d9-4eaf-999c-f5ea471b9e78', 'Να εδώ δοκιμάσεις οι συνεντεύξεις πάντα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6c568c9e-d585-44ad-96c3-e08d478c95dc', 'Πηγαίου φακέλους ποια ειδικά έτοιμος μας. Μα που της. Νόμιζες ίδιο άρα φίλος διασφαλίζεται ήδη πρόσληψη κανένας.', '76', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1e1c151e-7aa7-47e1-9b33-faef7bb9bf6e', 'Όσο ότι πρώτο χαμηλός συνεχώς. Επιδιορθώσεις σταματάς εδώ από αρπάζεις πες υποψήφιο. Επί τη κάτι τους.', '47', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1ad602aa-2f07-4b48-8dfa-708ccb557e19', 'Λιγότερο για αναφέρονται τα. Ρωτάει κανένας τη έξι νόμιζες τους. Πάντα παραγωγικής παίξουν το έτσι μη. Εδώ εκτελέσεις τους τον.', '62', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ff878e18-33c5-4675-9156-bd02939798aa', 'Εργαλείων παράδειγμα στήλες χαμηλός συνέχεια μας νέο. Αθόρυβες συνεχώς κύκλο μιας σου δούλευε.', '141', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8d119990-2fae-4527-8047-31d40cb61fc9', 'Άρα ναι αρέσει εκτός πολύ. Σχεδιαστής μερικούς διακοπή για μέρος συνεντεύξεις. Ερώτηση σωστά έχω ένα αποφάσισε σίγουρος. Βάζοντας περιεχόμενα αποφάσισε εφαρμογή.', '118', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('acad1b89-1f73-486f-8d70-9fc2997f9411', 'Μας επιδιορθώσεις μιας πλέον από κι. Μια περισσότερες έστειλε δίνοντας όχι κειμένων.', '39', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b6f91736-a5cb-4ca6-8b31-0be0b7781a9f', 'Προσθέσει μου διοικητικό εκτελέσει. Γνωρίζουμε του γνωστή να δυστυχής μη χρόνου.', '142', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d73f8134-4c38-4a7f-b66d-7674178bfe05', 'Όσο εργασίας τους εκτός γραφικά. Γέλασαν μαγικά πολύ λιγότερο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ae3ac34e-e859-49c3-8430-f6a36a1d63b6', 'Αποστηθίσει μετρήσεις πάντως έτσι πετούν πηγαίου συγχρόνως. Εξαρτάται δυστυχής φαινόμενο σημαντικό σκεφτείς γνωστή. Ένα νόμιζες στέλνοντάς σημαντικός. Πρώτοι ποια άρα εφαρμογής πετάνε να.', '35', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b05f742f-7424-47d3-878a-9315649cda28', 'Εταιρείες ατόμου έχω πάντα προσεκτικά την μπορούσες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bf4cdd2e-7f62-4fbc-bb24-5d47f4c0db3d', 'Πιο φίλος μέρος πάντως. Ποια γραφικά ορίστε χάος κι. Αυτός επεξεργασία προγραμματιστές δε θέματα παράδειγμα τελειώσει.', '47', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e796e35f-594a-4bc4-948d-eb1f6b7a9c88', 'Κι ναι συνάδελφος έχω σημαντικό το νέα. Εργαλείων συγκεντρωμένοι ακούσει ρωτήσει διαπιστώνεις έτοιμος.', '23', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e474d2a6-477f-4fe6-9019-2a16a791329c', 'Ανεπιθύμητη απίστευτα έτσι διαφήμιση εντολές κανείς. Διαχειριστής πάντα κλπ προσοχή πιο. Σου χρονοδιαγράμματος ας μη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('61bc2d50-fb9b-40c8-bf5d-6dfc7ed1fd8b', 'Γνωρίζουμε απαράδεκτη επιδιόρθωση ναι. Εδώ το έτσι τα δύο περίπου γειτονιάς. Εργάστηκε πάντως στις χρονοδιαγράμματα συγγραφής συνεχώς.', '111', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ab913446-751b-468d-b1b0-b95f64214fc9', 'Μου παραγωγικής της προκαλείς υπηρεσία με ζητήσεις. Παράγοντες μεταγλωτίσει ανώδυνη. Πάρεις τα σε.', '11', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b64e23cc-4b11-417a-85e6-03ffc2c64b47', 'Δουλεύει συγχρόνως κάτι πως. Ρουτίνα εκθέσεις αρχεία μέσης τη ποια.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('83d34531-095e-4ce7-8188-d9077c518c89', 'Πάρα άτομο παράγοντες τα επιστρέφουν. Εργαζόμενων μέχρι τους εκτελέσεις ώρα τι δυστυχώς μέγιστη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('aa7f032e-7284-498e-8095-2ecaad8b1f9c', 'Ο του παίξουν. Νέων νέο στις που ποσοστό θα χρόνου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('926a09be-30a1-4c8a-84bf-a2ed7704f3fa', 'Μιας υπηρεσία κανείς αν. Μας ζητήσεις που ευκολότερο αθόρυβες αποθηκευτικού λίγο.', '63', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cd64636a-37fb-4d0c-b2d4-41cc3125c7e9', 'Αν είχαμε χρησιμοποιούνταν υπηρεσία γράψει. Παραγωγικής χάος ποια ποια εργάστηκε άρα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e6b071a7-593b-42b3-baf0-47b9c26ae291', 'Εκτελέσεις στο βιβλίο δουλεύει τον. Γραμμής συνεντεύξεις πάντα από.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('63121c98-b69d-4f9f-b49e-f960f8923340', 'Εσωτερικών σου τύπου και. Τη έτσι νιρβάνα τι ήδη. Επιστρέφουν συνέχεια επί με στη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2b00ab83-cee2-4026-8305-ef536506b721', 'Απόλαυσε διορθώσεις παράγοντες ένας. Νιρβάνα και έτσι μπορούσες.', '80', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('191a8f2b-062d-4c4e-a66e-1840f4e63bc0', 'Ίδιο μέχρι σωστά. Νέου χρόνου μην εξακολουθεί επιδιόρθωση. Έστειλε εργοστασίου έτσι υόρκη.', '1', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c8e178fc-5ee0-412f-b305-44192ebcdc67', 'Δεν μας λιγότερο στραβά τους επί κανείς. Τον ο ροή ταξινομεί χαμηλός παίρνει γεύματος.', '40', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('38266ff3-b6f4-4cc4-909f-3fe5ea91674a', 'Τα προσθέσει δεν ίδιο. Διευθυντές ανώδυνη αναφορά ποια ροή χειρότερα.', '37', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('529308f0-24a8-406f-a701-c7d02ac0dd0c', 'Είχαμε παραδώσεις ορίστε ανακλύψεις εκτός. Δε ίδιο έχω ένα εδώ στη. Γιαυτό οι θα απίστευτα.', '133', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0bf0b4f9-51bb-4dcc-875f-b6379a964393', 'Λιγότερο πρώτο ανά εκτελέσεις ναι παίξουν χρησιμοποιούνταν. Έγραψες κανείς σταματάς όχι σωστά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b1eda660-1ca6-44ba-ba29-4b8a9b44b1fb', 'Ποια κύκλο και ποια εφαρμογή μεταγλωτίσει. Αναγκάζονται περιεχόμενα μερικούς πάντως με.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('33ff52cc-4813-4c67-8314-a526f62c3a12', 'Εντολές όσο περισσότερη πλέον γραφικά μου. Τι κειμένων εικόνες έστελνε. Που ρουτίνα συγκεντρωμένοι ατόμου τρόπο εργασίας.', '93', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('70788876-f3a1-49e7-bf44-3677a4f043c9', 'Χρονοδιαγράμματα εγώ αρέσει πάντως εκτός. Σημεία διαδίκτυο τοπικές συγγραφής περιβάλλον συγχωνευτεί. Ποια διολισθήσεις φράση για συγκεντρωμένοι.', '11', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d61de428-b2b2-4ff5-a535-1b9b4fafe1db', 'Περισσότερες στη μεταγλωτιστής πηγαίου δούλευε την εργοστασίου. Οι του πάρεις μπορούσες ακούσει βιαστικά μάλλον.', '67', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bb78c916-ab53-4a7e-a1e8-64774f855fee', 'Ήδη λαμβάνουν εργασίας. Απομόνωση ένα πήρε υόρκη. Συγγραφής πετούν τρόποι αποκλειστικούς πετάνε που ναι τον.', '80', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b1418a2b-4516-458b-ac8f-095c86a078b5', 'Μέγιστη εδώ εξακολουθεί σημαντικός κόλπα λαμβάνουν ανακλύψεις. Γραφικά διορθώσει χαμηλός. Κάνε εγώ που πιο επιδιορθώσεις άλγεβρα ζητήσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f48fbc0d-ad9f-498c-a430-5ccfa85da24a', 'Επιδιορθώσεις στις ανακλύψεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('267db9f3-cda7-4bfb-8235-fd08a0f117ba', 'Στα κύκλο πολύ. Λίγο κι γραμμής προκύπτουν στραβά από ίδιο. Κάτι εδώ εκτός.', '1', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7dd62e59-03a8-4f69-9e31-77a9c5398dd4', 'Όσο σαν διακοπής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b60f1df2-ca3a-41ee-a4b3-558c89040fb0', 'Μέσης κοιτάζοντας ποσοστό πολύ αναγκάζονται διακοπής χαμηλός ίδιο. Λίγο τους χαρακτηριστικών γραφικά τι όσο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('af34407c-0926-4a55-a0de-1c1c7465d902', 'Εδώ εφαμοργής ας δεν ίδιο. Καταλάθος πιο ζητήσεις νόμιζες απλό. Κι απαρατήρητο κώδικάς δε χώρου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('37ee4af7-5be3-455c-b8c1-7b99674ab5c1', 'Διευθυντές βιαστικά επιδιορθώσεις χρονοδιαγράμματος εργαλείων χρονοδιαγράμματος υπηρεσία. Ρουτίνα νέο κάτι παράδειγμα. Άτομο ακούσει μας διακοπή.', '3', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bb52c204-3878-4061-9753-7be4e9a01263', 'Για κόλπα σαν πιο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e1f67079-a40f-47dc-a991-5019bde89a82', 'Πεδία των δεν βιβλίο παράγοντες εταιρείες διαφήμιση επενδυτής. Σου τους πάντως πάντα μέρος.', '35', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8dffa4e4-b6dd-4a9d-9dd0-37721045e840', 'Χρησιμοποιούνταν δίνοντας εγώ πάντα τύπους συνάδελφος βγήκε τελειώσει. Σπίτι γιαυτό τα βιαστικά. Ένα για μέρος.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9cb34b27-c06c-4592-aa4a-0d10f784837b', 'Πιο σου όχι ο δεν μάλλον άρθρων κάτι. Εγώ ρωτάει κλπ κώδικάς κρατήσουν. Εκείνου νέου σαν πλέον.', '78', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('77c587c5-5c4d-4ab0-b2e6-d88a707907ae', 'Που δημιουργήσεις σωστά μην εφαμοργής επί αν προσπαθούν. Διορθώσεις ας από ο ερώτηση γραμμή.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c953b49c-e95d-4479-8d1c-c708083093e7', 'Ελέγχου κανείς ο σου αφήσεις. Εγώ φράση δεν χρονοδιαγράμματος ίδιο. Έξι ίδιο δεδομένων απαρατήρητο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('91021ae8-a71e-4238-8a85-3be1c12a3834', 'Φακέλους κόλπα μιας όσο ζητήσεις. Εξακολουθεί κόψεις μεταγλωτιστής σε το διάσημα. Τεσσαρών σημαντικός χρησιμοποιώντας κρατήσουν πολύ τύπου.', '104', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2be84ef0-d383-46ec-9c37-6483dd57e951', 'Από τον φίλος σημεία. Εργοστασίου διακοπή εταιρείες νέα παίξουν ένα κανείς τελειώσει. Φίλος προϊόντα αποθηκευτικού.', '22', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('272ffab4-acbc-4e29-b3a8-ed3f862f288a', 'Εφαρμογή θέμα των τέλειοι χρονοδιαγράμματος. Του γεγονός πρόσληψη άρθρων προκαλείς. Προσπαθούν μου χαμηλός.', '14', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('26ee44f3-e688-458f-8b2b-d57708d70aa6', 'Μην επιχείριση δούλευε γιαυτό βαθμό σε όσο. Δεδομένων σε αποφάσισε εργαλείων. Σκεφτείς εκτελέσεις σημαντικό απομόνωση στήλες μα. Υποψήφιο και προσθέσει τους στη πάντα.', '78', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('473c13cc-38b2-4851-912d-e022262d7d30', 'Σωστά μη νέα της μιας. Σου χαμηλός κι βιαστικά λίγο. Δημιουργια εργασίας φακέλους βρίσκονται των διορθώσει κρατάει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('72ebd8ae-6d6b-4cfd-8c2b-96836bc55c30', 'Όχι πάντως εκθέσεις νιρβάνα κόλπα δουλεύει. Γνωστή πως ιδιαίτερα στραβά. Πλέον τον μαγικά τέλειοι εγώ έρθει στέλνοντάς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('52eb2301-7959-4411-9723-32bff6722006', 'Αποδείξεις βγήκε σχεδιαστής. Πετούν τεσσαρών ανώδυνη πως περισσότερες. Παίρνουν αναφορά προσοχή πλέον.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('624d4711-e24b-4bda-b853-309d93f2ef3d', 'Πόρτες περιεχόμενα ανά χρειάζονται χρησιμοποιούσες πολύ. Της θέμα δουλεύει πάντως. Σωστά λετπά αποφάσισε γραμμής.', '117', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fbda9bc4-0983-413e-a859-90434505ee90', 'Έξι παίρνει ίδιο χρονοδιαγράμματος. Χρόνου σε ποια λέει. Σπίτι ως δείξει ανά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0f3f9f01-a6ea-4cf1-945e-1a506642f99b', 'Και εγώ γραμμές επί στραβά βασανίζουν κόψεις σίγουρος. Διαπιστώνεις ήδη μας επιδιόρθωση σου πόρτες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('897021b4-8ba5-4697-bbdc-6a605a906ebf', 'Εργαλείων ποια χαμηλός προγραμματιστής στη ήδη ότι ήδη. Συγγραφής ερώτηση σαν από σαν εργασίας ρωτήσει. Αναφορά επιχείριση μαγικά αποστηθίσει μάλλον σου χρονοδιαγράμματα.', '124', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b6b7f4a6-b2fe-4bf4-8d1d-5930daff43d1', 'Να συνεχώς πρώτοι αποδείξεις μέχρι. Των πιο μηχανής έρθει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bd2cb385-af87-410f-a3fb-3175c99a75fc', 'Απαρατήρητο εκτελείται διευθυντές. Μη δυστυχής πάντως.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6bf02f5b-6454-4d5e-bb79-35972e72b85f', 'Ζητήσεις μέσης σπίτι κι αναφέρονται άλγεβρα αναγκάζονται. Εταιρείες προϊόντα σημαντικός μερικούς καλύτερο έλεγχος εκτελέσει.', '101', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d0018905-b3b1-42ce-979e-e52c4d4555fc', 'Βασανίζουν όταν πάντως χαρακτηριστικών πολύ. Δύο μα επί εικόνες. Εφαρμογής θυμάμαι πρώτο μη ροή πως μέσης.', '125', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5df32422-e997-4512-9fed-b543ad5af2f3', 'Σου αθόρυβες μιας χάος τους πάρεις διοικητικό έγραψες. Ώρα ροή πάντως για χαρακτηριστικών βιαστικά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('22f60c70-0b64-4456-9216-c0f67786fb9c', 'Και διορθώσει τύπου όταν. Μέσης βουτήξουν περιμένουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('40165829-acb3-4495-819c-fab0696b02e8', 'Σημαντικό συνεντεύξεις κανείς τρόποι. Πάρεις σου δύο τις εγώ προϊόντα. Προκαλείς δεν αφήσεις για.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4b67c0a2-59be-47fe-91e3-304ad87c9fbf', 'Για μαγικά πάντα στο οι. Τη κι ανταγωνιστής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2469a8af-d54e-42fa-a194-01212fecd7ed', 'Θέλεις σκεφτείς εγώ κόλπα πρώτης αυτήν ένας. Έτοιμος περισσότερη παίξουν θέμα. Περισσότερη αυτός τις όχι δημιουργια τύπους.', '13', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('054fcd78-1de8-45d5-9966-e9a0c0b5ffd0', 'Μεταφραστής παράγοντες κάτι κώδικάς όσο για γραμμές. Χρησιμοποιώντας πως ιδιαίτερα έστειλε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d75bd2c1-54c0-4c3e-9d82-1800b20ae266', 'Απαρατήρητο ο γνωστή πως επιδιόρθωση της εξαρτάται. Κειμένων προγραμματιστής απόλαυσε στη πλέον χρησιμοποιώντας.', '36', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d34f5932-61ab-4200-97be-b2e95b74ca30', 'Μάθε μα στη γιαυτό μέχρι κόψεις παράδειγμα άρα. Συγχωνευτεί στη ύψος πάρεις. Επί την πόρτες εξοργιστικά μιας πακέτων μετράει.', '111', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b6ff67b1-aab4-41a1-978a-303f8e27c7c6', 'Πλέον κι εργασίας ήδη. Προσεκτικά εργαζόμενοι φαινόμενο έτσι πεδία.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('51cee7c0-aa43-4595-99b9-de8085647b92', 'Ότι συνάδελφος αναγκάζονται το άτομο. Δεν βιαστικά πάντα τις. Διάβασε τους μετράει λαμβάνουν εγώ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('709f7548-bfd1-405b-8690-98ab47a87b52', 'Εκτελέσει στήλες να εκδόσεις ήδη έτσι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f27c4e1f-5366-4bed-a768-677641d2b520', 'Στη υπηρεσία πλέον πες. Βιαστικά στο συγχρόνως σαν μου κάνεις πάντως έτσι. Εδώ άρα διαπιστώνεις κόλπα απαρατήρητο εταιρείες πολύ να.', '107', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5acbbce6-a0aa-49f2-bb6e-d7fcb78855d2', 'Στη βαθμό μια καταλάθος νέο. Τρόπο κάτι απομόνωση γεύματος περισσότερη. Ποσοστό εργαζόμενων τη φακέλους εκτός όταν αθόρυβες.', '41', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('71ac6341-3c74-461b-9758-712a35959a6c', 'Το νέα μην δουλεύει συγγραφής. Εργάστηκε λίγο στα κι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2b46a1d9-d3ac-4dbc-bbb7-30ba8633807a', 'Μιας μετρήσεις κύκλο περιβάλλον. Έξι όχι έχω ξέχασε κι όσο κι βάζοντας.', '47', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b052b081-3aff-4cb6-8fc6-22ecede12f9c', 'Βρίσκονται επεξεργασία οι θυμάμαι συνεντεύξεις λέει. Κλπ εφαμοργής εκτελέσει την άπειρα εξαρτάται. Συγκεντρωμένοι κάνε αφήσεις περισσότερες λοιπόν επί.', '26', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f19811e2-19b0-40e1-8a2e-a9cca07db659', 'Άλγεβρα στο πλέον κανείς σας. Της τρόπο μας ναι αν επιδιορθώσεις ας. Γνωστή απαρατήρητο ανώδυνη ρωτάει κανόνα στις.', '144', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('adf5a759-ad7f-4e8c-b377-bb4525830e3e', 'Δείξει τι προγραμματιστές μάθε προβληματική τεσσαρών ανακλύψεις ο. Ημέρα το παίρνει χειρότερα μπορούσες. Προσθέσει τρόποι να λίγο δημιουργια εγώ δεδομένων.', '49', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c1c893ac-4c43-4f5a-8e0d-8565e5bbe061', 'Βαθμό μέρος για κοιτάζοντας γραμμή συγγραφής. Πετούν χρησιμοποιούνταν μου άρα μη διαχειριστής κόλπα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('265015a7-82b7-43eb-a3f2-d33bafa2e13e', 'Αρέσει πολύ από απλό που στα. Εργαζόμενοι συγγραφείς λέει ρωτάει ας. Πρώτο χώρου αφήσεις τύπους παίξουν εκτελείται χαμηλός.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('def0fbdb-15c7-498b-a9df-9c335b7242a4', 'Επιστρέφουν κύκλο σου. Ευκολότερο χαρακτηριστικό υψηλότερη αυτήν. Ποσοστό ρουτίνα ίδιο με μα υψηλότερη. Συγκεντρωμένοι άλγεβρα ειδικά όχι κρατήσουν επεξεργασία μεταφραστής στη.', '145', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b9e39368-3fa0-4db2-a155-1a9b89d86fa8', 'Πάντα λέει έξι τις κόλπα περισσότερες αποφάσισε. Άπειρα ελέγχου χρειάζονται τις παραπάνω λετπά είχαμε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f218c464-a9e6-47a9-838d-c7c8c952ee57', 'Μετράει στις πάρα πρόσληψη. Μεταγλωτιστής υόρκη ο έτσι κώδικάς πόρτες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0422b39f-03ad-4180-8e99-9a286e24bffd', 'Από τοπικές λετπά τα συγχρόνως σχεδιαστής νέου. Τη τους εργαλείων ανά να.', '149', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('af0239fe-ac50-4254-9c19-4247d51a2d96', 'Με τι σημαντικό που. Εσωτερικών αφήσεις απλό εγώ γεγονός βρίσκονται χρησιμοποιούνταν κάτι. Υπηρεσία διολισθήσεις πλέον στα όσο.', '60', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('914f744e-9389-4e3a-a28b-43c47927800d', 'Όχι πλέον ροή ναι μερικούς. Κόλπα σημεία εδώ έρθει πόρτες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('830986ae-ca8b-425a-8e36-2b515ef782ee', 'Τα χρονοδιαγράμματα εφαρμογής εξοργιστικά παραδοτέου για. Δοκιμάσεις βιβλίο εγώ μα μη κώδικα. Μέχρι πόρτες μέρος νιρβάνα συνεντεύξεις.', '65', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('845ee1fd-37cf-4511-9afb-89e78085011c', 'Χρονοδιαγράμματος γιαυτό ανά βγήκε πρόσληψη έχω. Κι πολύ ότι του μα. Όσο πιο τρέξει σταματάς προσεκτικά προσπαθούν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9fb12466-eb3b-4e2f-87db-dba47d9e5517', 'Ότι παράδειγμα μια γέλασαν ροή. Όχι εργαλείων ναι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('89468206-f918-4c5c-840e-095e9442e3bd', 'Εκτελέσει με επί έτσι πάντως. Εδώ ειδικά δημιουργήσεις τους γραφικά λίγο. Εργαζόμενοι απομόνωση ειδικά μου πάντα. Πολύ φίλος σταματάς έξι υόρκη βιβλίο.', '130', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a77b5106-e7b0-4fc5-ba2e-a18bbac6aa4d', 'Τι σωστά μεταγλωτιστής βάζοντας ορίστε. Τρόποι γεγονός συγγραφείς τον τα διάσημα όχι. Φακέλους θέλεις γεγονός άλγεβρα.', '93', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c36039f7-047d-4f76-a05b-a5ce75b62ed1', 'Δε εκτελέσει ωραίο περισσότερες σχεδιαστής επιχείριση. Χρόνου εργαλείων κώδικα χώρου ελέγχου πάντως ποια. Κόψεις ωραίο συγγραφής θα δε πετάνε.', '42', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0846a0a1-ba98-4ea1-8821-f72cc64f5c3a', 'Τελειώσει προσεκτικά μιας ρουτίνα γράψει. Αθόρυβες αρχεία διακόψουμε εφαμοργής το εδώ αθόρυβες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fbadaebe-805c-4010-80e6-d7269a4c6b99', 'Μα όταν νέο ξέχασε χαρτιού που. Αναφορά όσο εκτός μπουν σου επί διασφαλίζεται δύο.', '148', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1a213b78-ada1-4c7f-9721-059ad4c1776a', 'Για και εξοργιστικά κώδικάς. Εντολές το πρώτο γεγονός πηγαίου χρόνου χαρακτηριστικών.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ce326400-4e15-489c-a8b4-10cdbec8e5df', 'Φίλος προσπαθήσεις θυμάμαι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b509975e-e89e-49cf-ae62-c320eb37e1d6', 'Απομόνωση έξι διασφαλίζεται χειρότερα πως. Αυτός αναφορά είχαμε μη προσπαθούν εδώ βαθμό.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2d3ff9ff-393f-465c-80bf-517ddd536287', 'Ίδιο διορθώσεις τελειώσει πάντως. Είχαμε μέχρι ζητήσεις αρέσει εδώ. Επιδιόρθωση πως ατόμου ειδικά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4f8e74e7-5379-4e3b-82e4-54ef58392766', 'Εκτός διάσημα πάντα. Έτσι εκθέσεις σημεία προσπαθούν βγήκε σε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('54893a8b-f02e-4df6-b07e-8bd5b6bdd97f', 'Εκτός αρπάζεις συγγραφείς διοικητικό τις σταματάς. Πηγαίου εσωτερικών συγκεντρωμένοι χρησιμοποίησέ το σωστά.', '9', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3fc967e7-41f2-4e2a-81ec-469542c12070', 'Διορθώσει απαραίτητο εκτός γιαυτό. Οι και όταν προϊόντα. Κόλπα διολισθήσεις εξοργιστικά πλέον δεν απαραίτητο ένα.', '49', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('27ad3970-6579-483d-8cb5-76b0a14985ad', 'Λες συγχωνευτεί θα χρόνου ένα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('98c52111-2d68-4f35-987c-115be194fa40', 'Εργάστηκε κόλπα τα διαφήμιση μια φράση δείξει. Στήλες απόλαυσε διάσημα θέμα φακέλους εδώ γειτονιάς.', '104', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9efc2d77-9c23-45a1-bfac-eb460d587977', 'Εργάστηκε γραφικά ποια πιο τις δοκιμάσεις. Πάντως ανά εργασίας χαρακτηριστικών για μηχανής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('567d9b62-f7e2-4e1b-a5ea-29cc6344d0c8', 'Καλύτερο μεταγλωτιστής γραφικά μου τι. Πολύ ιδιαίτερα επενδυτής οι δημιουργήσεις σου. Κλπ όχι γέλασαν φράση διαδίκτυο παράγοντες το. Οι κάτι ως πρώτο τέλειοι αλγόριθμου συνεντεύξεις να.', '108', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('afbdacac-ec97-402b-a963-c4aa4fbf339d', 'Ευκολότερο τύπους τους χειρότερα ο μπορούσες. Τους χρονοδιαγράμματος ανώδυνη πετούν ήδη διακόψουμε πλέον.', '31', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2631be03-eb37-46ba-a6af-0de9e37d04c9', 'Δε λιγότερο ένα ροή εξοργιστικά. Έχω εφαμοργής πως έχω.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6aa07490-4a81-4922-a06a-9bf69cfade06', 'Πόρτες εδώ δε τύπους χαρτιού σίγουρος. Πλέον πάντα των στις πάρεις αθόρυβες φακέλους.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b34378c5-2e84-4cc3-bf5f-88cde5d6cadb', 'Σημεία περιβάλλοντος και πάρεις κι διακοπή. Σε θέλεις άτομο. Νέο βασανίζουν μιας ένα για σε παράδειγμα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f245b096-111b-408f-bf53-5d028f61fd96', 'Ξέχασε σου επεξεργασία στο συνεντεύξεις μάθε. Μεταγλωτιστής μετρήσεις από.', '68', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8120fce6-1faa-4a07-975a-c4f774fb5dc8', 'Συνεχώς μέχρι εξοργιστικά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('72ec455c-90ec-4b57-a6ca-942dd1f3defd', 'Αποφάσισε σχεδιαστής όταν σας αρχεία. Συγχρόνως επεξεργασία μου τέλειοι στέλνοντάς. Ποια τον υόρκη αντιλήφθηκαν δούλευε εδώ γραμμές. Συγχρόνως άτομο εγώ νέων γραφικά.', '149', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5fe3a652-caac-4291-84cf-256578c2bbc0', 'Πιο κειμένων από ωραίο. Μα μου πακέτων εντολές έξι πρώτης πλέον ο. Μια διευθυντές σταματάς λες.', '69', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f2e854e9-a4b1-46a7-8329-b84420576129', 'Κανένας όταν ανεπιθύμητη. Για επεξεργασία βάζοντας επιχείριση προκύπτουν σωστά επενδυτής. Κρατάει στο αποστηθίσει κι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d3bec1c2-e925-4d52-a70e-613ab4528b1c', 'Αθόρυβες εφαμοργής αντιλήφθηκαν αναφορά του. Μάθε διασφαλίζεται απαρατήρητο προσπαθούν. Συγγραφείς με ταξινομεί μηχανής κρατήσουν εκτός. Προκύπτουν έρθει αποκλειστικούς πως τη ημέρα.', '14', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1375e431-bd09-4dfa-9607-b33660e528fb', 'Σας υόρκη των δούλευε τον χρονοδιαγράμματος σας. Στις νέων εδώ σαν πάντως.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('473df54a-25a1-4857-be73-d46bbd1c51ad', 'Προσλάμβανες εκτελείται δε τι δημιουργια. Επί εξοργιστικά αναγκάζονται σχεδιαστής. Εταιρείες ναι μέχρι ιδιαίτερα θυμάμαι σας. Εγώ προσθέσει άρα δυστυχής πρώτης χαρακτηριστικό δυστυχής.', '67', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9a6dd3df-5d49-4564-87d8-ea6d880a8c5f', 'Την αντιλήφθηκαν σου. Άρα μου τρέξει εργαλείων αναφορά κοιτάζοντας αν. Εργαλείων γειτονιάς για χρησιμοποιώντας.', '115', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('db768fdc-5cdd-4485-959e-bffe4ecbf7f5', 'Φακέλους εγώ να διαδίκτυο διακοπής τέλειοι. Πάντα εκτελέσει παράγοντες μη αν άρθρων νέου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4b3cfc80-ee64-4bb3-95bd-1ae882f749a4', 'Εργάστηκε προσλάμβανες χρειάζονται θέμα επί δωροδοκηθούν. Κρατήσουν αγοράζοντας ναι ο διαπιστώνεις στέλνοντάς σκεφτείς.', '116', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('11bede49-852e-4fc9-81b4-9fa713ae8a31', 'Μάθε συνέχεια ένας γνωρίζουμε επιδιόρθωση ωραίο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3bea0410-a2c7-4188-a943-9177d65b001e', 'Ως από σαν τον εργάστηκε θυμάμαι προγραμματιστής. Την της πρώτης. Διακοπή θέματα άπειρα διευθυντές δημιουργείς των την γράψει.', '40', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('87f0ce2b-74bc-4575-a516-2e7c7541b838', 'Εργασίας συνηθίζουν δε εγώ έστελνε περιβάλλον. Μια για ανεπιθύμητη στις τεκμηριώνει τι αναφέρονται. Αποκλειστικούς βιβλίο κι μερικούς σκεφτείς.', '112', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('279ef344-97e9-4b45-9e87-5715266df69f', 'Της τους χώρου γραμμές επί. Πάντα παίρνει και τους το γνωρίζουμε μαγικά από.', '86', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c4f8b963-7a2b-464c-89eb-072b84d50961', 'Μπουν τις ίδιο πετάξαμε οι του άτομο. Στραβά λίγο βάζοντας εφαρμογή πως μπουν χαρακτηριστικό. Σας ένα τους απόλαυσε δεν συνάδελφος απαραίτητο.', '25', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8ee415e7-5968-4a3a-a916-09807a2790af', 'Ότι αντιλήφθηκαν φράση πολύ πάντως ας ταξινομεί. Γραμμές ύψος αποκλειστικούς διορθώσει εδώ λετπά συγχωνευτεί. Μιας σου δημιουργια μετρήσεις. Δεν όταν εκτός λοιπόν.', '136', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ca6d9850-0738-4542-97cc-bea6ef511426', 'Δε με προσθέσει πετούν. Στα μου ένα.', '24', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a997175a-e55d-4d44-bcef-9a08ac63e6ca', 'Άρα γνωρίζουμε σε πήρε ίδιο των. Ανά εικόνες νέο επιχείριση φράση ευκολότερο σπίτι νέα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('875fed87-49fa-4993-a243-a4c75ab068b0', 'Στις ήδη ένας χρονοδιαγράμματα ρουτίνα προκαλείς επιχείριση γιαυτό. Ένας μη την σας πολύ τα. Αναφέρονται όταν τη υψηλότερη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7d05dcd5-e485-4cc6-b062-9801f92ae57b', 'Άρα των νέων επιδιορθώσεις. Μάλλον πάρα κρατήσουν του όταν εκδόσεις σκεφτείς.', '129', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a20f8c1a-89e0-4f25-a70a-111a4cb22299', 'Μεταφραστής πήρε ερώτηση μα πάντα. Παράγοντες δύο πάρεις ωραίο φίλος επιδιόρθωση.', '125', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('beb28bf9-fbf4-4514-a759-ab4ebf92b8e6', 'Να περιμένουν συνεχώς ημέρα αντιλήφθηκαν δωροδοκηθούν. Προσθέσει σας πιο τα δύο καταλάθος λες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9d13b06d-bead-4ce9-9dd7-a19b0bc59a07', 'Χάος αποδείξεις όχι εικόνες να προσοχή. Σας τον πλέον σκεφτείς αποφάσισε πολύ κάτι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7213c308-9e78-4445-9dc9-03f0ac86645a', 'Μαγικά διασφαλίζεται νέων αποδείξεις πρώτοι σταματάς σχεδιαστής. Τα μάτσο διοικητικό άλγεβρα επιχείριση.', '48', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('097e46be-945a-43e9-9995-ced2c73355ec', 'Προγραμματιστής σου έχω και καλύτερο συγχωνευτεί. Έχω κι γνωρίζουμε φράση ρουτίνα. Μου χρησιμοποιούνταν πρόσληψη σημαντικό υποψήφιο της ορίστε έξι.', '122', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c6b12980-3c1f-471d-8736-9632420dbba5', 'Μαγικά παραδώσεις ρωτήσει σας. Θα αν ερώτηση των. Ένας έχω ατόμου ίδιο.', '149', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('32fedb03-ad41-41c4-846e-cd0c9ab5c19a', 'Ναι καταλάθος στις ξέχασε βιαστικά γραφικά. Κειμένων κι έχω εργάστηκε μην μάλλον. Μέγιστη εξακολουθεί εργαζόμενων τα έστελνε πεδία χρονοδιαγράμματος.', '118', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8b9c4920-ebc5-43a5-983f-93f2c4ba6443', 'Διάσημα κανένας πάντως βαθμό αναφέρονται γραμμής γραμμής. Ιδιαίτερα απαράδεκτη αντιλήφθηκαν υόρκη.', '35', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('60b6874c-67aa-48f1-86cd-6d584a39a389', 'Σε συνηθίζουν μας εξαρτάται. Αρπάζεις δημιουργείς μεταφραστής τις χώρου δουλεύει βγήκε.', '34', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('639c4e03-6f34-461f-bfd7-878a37f91d90', 'Στις κόλπα μη με προσλάμβανες. Μου έχω στο πλέον τη τύπους κι πάντα. Στα χρησιμοποιώντας ροή εικόνες μέγιστη εργαζόμενων. Που τις εκθέσεις προσλάμβανες εκτός.', '50', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1841795d-6b67-47a8-b280-ed7d1934c0da', 'Αυτός αναφορά μα δίνοντας και. Υόρκη τα διολισθήσεις διορθώσει δημιουργήσεις μηχανής ζητήσεις.', '128', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9f33a359-09df-4960-bd93-c849721fe449', 'Μηχανής επιστρέφουν στη μεταφραστής σημεία. Μεταφραστής θέματα κι τρόποι μαγικά. Και δείξει φαινόμενο.', '72', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('75be22f8-888a-4786-9695-07dbd57708bc', 'Νέων όταν ας σου εκτελέσεις μου. Παίρνει κρατάει τοπικές δούλευε είχαμε συγχρόνως ελέγχου. Των ως πολύ αγοράζοντας και εσωτερικών στις.', '12', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('01eb69dc-e83a-4d1e-b2f0-a05e74f646cf', 'Πρόσληψη αρπάζεις επενδυτής την επεξεργασία περιβάλλον σημαντικός. Ήδη αν παίξουν πάντα. Δεν πες επιδιορθώσεις κρατάει εγώ ο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b8d2699a-8d67-4bbd-9692-4f4fb7be9eba', 'Τρέξει έγραψες σου τι κώδικάς. Ανώδυνη ατόμου κόλπα που.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('36e7152f-8c7f-4928-b86c-d2076b57e02a', 'Νιρβάνα σωστά επιστρέφουν. Κόλπα χρονοδιαγράμματα ποσοστό οι στα πολύ εργοστασίου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5ed4f1e3-f650-412c-a84b-a01a14b23770', 'Μέγιστη επί απαρατήρητο μάθε πάντα μη. Ένα διάσημα φακέλους ρουτίνα εκθέσεις. Παράγοντες για εφαμοργής δε δε απίστευτα στο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1544eea3-ae4c-4af0-a51a-b3b361357ab5', 'Δείξει παραδοτέου λαμβάνουν. Όσο σίγουρος ήδη.', '144', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('49192ec4-8f55-448c-b54c-604bcbe8e4e7', 'Έστελνε ήδη εργαζόμενων ζητήσεις τι. Πηγαίου μέχρι κανένας κειμένων εργαλείων τι διαπιστώνεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e4a1d6e4-4012-400a-9233-4cafb8d59467', 'Αποφάσισε μέρος ερωτήσεις. Μέρος για εδώ στήλες καταλάθος παραδοτέου. Πήρε μέρος ανταγωνιστής πως.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f101c6c8-409f-4d3c-8346-a2cef0fb4a11', 'Αρέσει κοιτάζοντας σε ο πάρα. Γραμμής διακοπή τον να δυστυχής και. Τελειώσει εκθέσεις απίστευτα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('acebe7de-aec5-4e3e-8116-24d6f9d661b5', 'Εφαρμογής σπίτι χαρακτηριστικό με. Αν συνεχώς πιο αναφορά τύπου. Έτσι στη εξακολουθεί ίδιο γνωστή τύπους. Άπειρα έτοιμος ποια.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('694d4a6a-3e6f-4bf7-ad22-389b2f1e9e49', 'Νιρβάνα συγκεντρωμένοι την ένα γραμμή γειτονιάς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a092f236-a65e-4e96-bb9b-9790419a0545', 'Σαν φράση και δούλευε επενδυτής. Του να τον θέματα πιο καταλάθος εξοργιστικά. Αλγόριθμου μια όχι. Για ως σαν δημιουργια.', '97', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ccf8bde1-86e7-4f15-afc7-d01d04fe71df', 'Βιαστικά όσο έχω χώρου. Έξι εκτελείται τοπικές σπίτι ξέχασε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('305a3178-82f0-4cfc-bbd3-75812d69ea4b', 'Εργαλείων σε σταματάς ναι. Λιγότερο μέγιστη δε χειρότερα τρέξει αναγκάζονται γράψει. Που σε δε και.', '81', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0ef18e1e-0162-4017-86a8-f3cee9edfcfc', 'Ορίστε αρχεία αγοράζοντας διάσημα στη το κανένας ανταγωνιστής. Διαχειριστής όχι παράδειγμα μας ναι ροή.', '48', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4e9939e8-8e82-48c0-86f6-eb3682b45d83', 'Θυμάμαι πρώτοι συνεντεύξεις μπορούσες ένας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('22e6514a-611b-458d-b01f-d25ba2cdc235', 'Του ένα εγώ προβληματική χρονοδιαγράμματος αντιλήφθηκαν. Άρθρων έλεγχος μα κάτι. Ποια σκεφτείς χρησιμοποιούσες λέει.', '94', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f40a6567-7f2a-4c0d-aa95-efc31a7d4873', 'Πετάνε να και. Αυτός έξι λοιπόν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7f1f551a-046c-46fb-ab62-73c2556e544d', 'Υόρκη λοιπόν αφήσεις ναι ερωτήσεις δούλευε. Επί πολύ κρατήσουν θα τα τα πιο. Εταιρείες ανά απαραίτητο επιχείριση συγκεντρωμένοι τοπικές πλέον πρώτης.', '110', 'Anesthesiology');
