INSERT INTO media (media_id, path, description) VALUES ('586', '/media/images/image_tempore.jpeg', 'Μέγιστη περιβάλλοντος δίνοντας κάνεις κώδικα βάζοντας κι ώρα. Μας στη διασφαλίζεται. Οι εκδόσεις κανένας παίρνει κάτι μαγικά δίνοντας εφαμοργής.');
