INSERT INTO media (media_id, path, description) VALUES ('587', '/media/images/image_veritatis.jpg', 'Αρχεία κι ελέγχου. Τεσσαρών διαπιστώνεις μας χρησιμοποιούσες. Μέγιστη ημέρα φακέλους χρειάζονται σε να.
