INSERT INTO media (media_id, path, description) VALUES ('588', '/media/images/image_accusantium.jpg', 'Εργαζόμενοι παράδειγμα προσεκτικά από μιας πολύ κανένας. Έγραψες εταιρείες έρθει εξακολουθεί. Δυστυχώς τις πολύ διαφήμιση τον εδώ γραμμές.');
