INSERT INTO media (media_id, path, description) VALUES ('589', '/media/images/image_pariatur.jpeg', 'Συγκεντρωμένοι αλγόριθμου τους σχεδιαστής. Εκτελέσεις εδώ γνωστή πάντως δίνοντας διάσημα. Διορθώσει κλπ παραγωγικής πήρε εργαζόμενοι μπορούσες απαρατήρητο.');
