INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('1', '150065', '2024-02-24 00:00:00', '2024-02-27 00:00:00', 'Μην πολύ εκτός καταλάθος ο ημέρα διοικητικό. Που εκτελείται στραβά εργαλείων όσο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('2', '0810507694', '0105502012');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('2', '72076', '2022-04-01 00:00:00', '2022-04-05 00:00:00', 'Ένα μην μετράει αναγκάζονται καταλάθος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('3', '2101937959', '0308447051');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('3', '105929', '2021-11-08 00:00:00', '2021-12-02 00:00:00', 'Πως στήλες καλύτερο κάνε. Και πρόσληψη εκτελέσεις ίδιο εγώ ως ορίστε.', 'Δίνοντας μερικούς πολύ συγκεντρωμένοι απίστευτα στα μπουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('4', '0705997672', '3010682905');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('4', '46469', '2024-09-07 00:00:00', '2024-09-27 00:00:00', 'Εκτός δίνοντας αρχεία ποσοστό. Χαρτιού εργαλείων άρα πες τοπικές έχω διαδίκτυο διάβασε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('5', '0911733292', '2110730914');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('5', '114614', '2025-05-15 00:00:00', '2025-05-30 00:00:00', 'Δυστυχώς ποια εκτός πολύ ταξινομεί εκτελέσει. Εκδόσεις απομόνωση νέα ανεπιθύμητη. Περισσότερη σε ο τέλειοι.', 'Κάνε μέχρι θα την.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('6', '2807932946', '0103833094');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('6', '74206', '2022-07-03 00:00:00', '2022-08-29 00:00:00', 'Αποφάσισε εφαρμογή ας εξοργιστικά γραμμής κύκλο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('7', '1706483980', '1610064691');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('7', '82972', '2022-12-25 00:00:00', '2023-02-17 00:00:00', 'Τους επιστρέφουν νέων αποκλειστικούς εκτελέσεις. Την εκτός επεξεργασία διοικητικό τρέξει πρώτοι υόρκη κειμένων. Προγραμματιστές λαμβάνουν λαμβάνουν ποσοστό στήλες.', 'Στα χρόνου συνεντεύξεις χρόνου γιαυτό.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('8', '1507519992', '0704149555');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('8', '83601', '2022-02-28 00:00:00', '2022-04-05 00:00:00', 'Έξι για έχω προγραμματιστές μη περίπου μέχρι. Τη έτοιμος κύκλο εγώ φαινόμενο μέσης. Καταλάθος μη ωραίο ότι έτοιμος επενδυτής υψηλότερη μια. Χρονοδιαγράμματα απλό αθόρυβες για προκαλείς μέχρι λες.', 'Ποσοστό θέματα δωροδοκηθούν περισσότερη πάντα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('9', '2310497857', '2804224069');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('9', '148870', '2024-03-22 00:00:00', '2024-03-25 00:00:00', 'Εγώ δεν στέλνοντάς τον πεδία ανταγωνιστής σαν. Πάντα διαπιστώνεις θέμα.', 'Ύψος στις απαράδεκτη όχι ένα χρονοδιαγράμματα από.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('10', '2702666773', '2812710195');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('10', '14102', '2023-09-29 00:00:00', '2023-10-11 00:00:00', 'Δύο περίπου όχι δημιουργια υόρκη μια γραμμής κανείς. Λετπά μου ας αν. Λετπά ρωτήσει νόμιζες γέλασαν ας γεγονός.', 'Μιας ταξινομεί έξι και σαν εργασίας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('11', '2305001120', '0108927665');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('11', '129276', '2026-01-17 00:00:00', '2026-02-27 00:00:00', 'Εκτός αποφάσισε από βιβλίο τα συνεντεύξεις σας. Συγχωνευτεί γνωστή των ξέχασε πάντως.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('12', '1606531841', '1010942280');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('12', '40492', '2023-01-02 00:00:00', '2023-01-20 00:00:00', 'Στέλνοντάς και τρόπο σας δε. Διαπιστώνεις τι περιβάλλοντος πεδία. Ατόμου μέσης γράψει βαθμό χρησιμοποίησέ κι αθόρυβες.', 'Περισσότερες αποκλειστικούς εργοστασίου επιδιορθώσεις έτσι. Ποια μια έστειλε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('13', '1106837316', '0201768300');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('13', '142657', '2026-10-25 00:00:00', '2026-11-15 00:00:00', 'Δοκιμάσεις δίνοντας προγραμματιστές έχω αν. Προσπαθήσεις κανόνα από εσωτερικών προσθέσει μάτσο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('14', '2204731625', '0511711784');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('14', '95412', '2026-02-26 00:00:00', '2026-03-31 00:00:00', 'Και λετπά πλέον μη άτομο. Βάζοντας όχι προγραμματιστές.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('15', '0307516056', '3012928959');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('15', '8780', '2021-04-28 00:00:00', '2021-06-13 00:00:00', 'Βασανίζουν τι πάντως πλέον εικόνες χαμηλός. Βασανίζουν μέχρι πως χαρακτηριστικών μεταγλωτίσει. Πιο δημιουργήσεις μια δεν γνωρίζουμε.', 'Λετπά νέα μαγικά κανένας άτομο προκύπτουν. Ποσοστό τον της ανταγωνιστής δεν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('16', '0104572116', '2211239878');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('16', '114704', '2026-12-23 00:00:00', '2027-01-06 00:00:00', 'Εργοστασίου μάτσο έτοιμος θέματα τρέξει έστελνε δε ερωτήσεις. Επί ανακλύψεις πλέον σαν ότι πολύ. Μα χαρακτηριστικό πιο εξακολουθεί διακοπής πάρεις. Πιο ύψος άτομο κάτι ρουτίνα εκτελέσει στο χρόνου.', 'Τις περιμένουν χαρακτηριστικό πάντα χαμηλός.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('17', '2305001120', '0304180463');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('17', '131843', '2023-03-14 00:00:00', '2023-04-19 00:00:00', 'Μάθε τα μέχρι δε μεταγλωτιστής δεν αυτήν σωστά. Περιεχόμενα πηγαίου ρουτίνα υποψήφιο τελειώσει διαχειριστής. Εκτελέσεις ανταγωνιστής τη μιας ας διευθυντές.', 'Έξι ίδιο χρονοδιαγράμματα ποια ορίστε γραμμής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('18', '1709001822', '2805627622');
