INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('19', '0104945542', '2211239878');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('19', '29910', '2024-12-20 00:00:00', '2025-01-26 00:00:00', 'Ιδιαίτερα χρησιμοποιώντας που δε διολισθήσεις νέου. Αποκλειστικούς απαραίτητο εκείνου τεσσαρών ως.', 'Νέων κι σαν ότι εντολές.');
