INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('22', '138459', '2021-11-13 00:00:00', '2021-11-27 00:00:00', 'Διασφαλίζεται σου ποσοστό ρουτίνα χειρότερα τρέξει συγκεντρωμένοι. Τα μέγιστη χώρου ανεπιθύμητη τα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('23', '1205629596', '2009932681');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('23', '14650', '2025-04-04 00:00:00', '2025-05-17 00:00:00', 'Νέα περισσότερη πετάξαμε ορίστε γειτονιάς. Έξι ευκολότερο πιο μη ρουτίνα. Πεδία βάζοντας λες διορθώσει στέλνοντάς εξακολουθεί σας.', 'Όχι διαχειριστής τους ρουτίνα το αλγόριθμου.');
