INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('28', '1707411678', '2510150800');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('28', '3677', '2021-08-21 00:00:00', '2021-10-07 00:00:00', 'Σας θέλεις παραδοτέου σωστά προσπαθούν μερικούς έγραψες δε. Πως κύκλο πρώτοι εξακολουθεί χειρότερα δεν σίγουρος. Βάζοντας κι από κάτι για.', 'Μου εκδόσεις μου εξακολουθεί. Τη συνηθίζουν που προβληματική θα.');
