INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('29', '2266', '2021-02-28 00:00:00', '2021-03-16 00:00:00', 'Θέματα υόρκη λίγο θέμα. Εκτελέσεις μέχρι αφήσεις ναι διολισθήσεις. Πρώτοι δουλεύει διακοπή τι να νέο εξακολουθεί.', 'Εγώ εκτός στραβά γνωρίζουμε πηγαίου αθόρυβες εκτός σου.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('30', '0307571050', '1709104543');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('30', '149940', '2026-10-10 00:00:00', '2026-12-08 00:00:00', 'Την σε έξι μη αυτήν χρησιμοποιούνταν ποια. Γραμμές μεταγλωτιστής μιας ποια.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('31', '2201663505', '2112057954');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('31', '122561', '2025-10-04 00:00:00', '2025-10-08 00:00:00', 'Μια πως ποσοστό σαν αντιλήφθηκαν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('32', '0110417536', '2211239878');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('32', '146242', '2020-11-18 00:00:00', '2020-11-22 00:00:00', 'Σπίτι μπουν διαχειριστής στη βάζοντας απλό. Αρπάζεις διάσημα ακούσει γραμμές μέσης έτσι ζητήσεις. Δύο νιρβάνα πως κοιτάζοντας χειρότερα όσο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('33', '1507519992', '0305655483');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('33', '107367', '2021-03-28 00:00:00', '2021-05-27 00:00:00', 'Ο γεύματος σας αποστηθίσει διορθώσεις τρόπο για. Ανώδυνη περισσότερες πάντως χρονοδιαγράμματα πάντα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('34', '2305001120', '1005685406');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('34', '2975', '2026-11-19 00:00:00', '2027-01-16 00:00:00', 'Τι εκτός κρατάει έτσι. Παραδώσεις απαρατήρητο δοκιμάσεις. Ταξινομεί στις κι εκείνου περιβάλλοντος πηγαίου.
