INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('35', '107658', '2021-01-26 00:00:00', '2021-02-11 00:00:00', 'Συνέχεια προϊόντα τι από. Νιρβάνα διακοπής κώδικα ελέγχου τι έχω.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('36', '1706483980', '1603433260');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('36', '56978', '2025-09-06 00:00:00', '2025-11-03 00:00:00', 'Επί όταν πηγαίου τα στις στα αποφάσισε. Επί απομόνωση μου ώρα αποστηθίσει σταματάς δυστυχώς.', 'Προγραμματιστές πεδία εξοργιστικά με.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('37', '2805925031', '0707048882');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('37', '109638', '2023-05-15 00:00:00', '2023-06-02 00:00:00', 'Πως πως επιδιόρθωση μεταγλωτιστής στη ρωτήσει πολύ. Για πετάξαμε ερώτηση πως χρονοδιαγράμματα.', 'Του μάθε δε χαρακτηριστικό διαδίκτυο προσθέσει τους.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('38', '1908859928', '2811912804');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('38', '128415', '2024-10-22 00:00:00', '2024-11-12 00:00:00', 'Βγήκε έχω συνεντεύξεις αθόρυβες μιας που. Νέου κόψεις από κλπ ένας σου επεξεργασία. Εικόνες στα έχω δοκιμάσεις δύο δούλευε. Κανόνα πακέτων έξι κανένας κάτι υπηρεσία.', 'Άλγεβρα μάθε έτσι έχω. Εκτελέσει δύο σαν αποδείξεις βαθμό την.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('39', '2107830903', '1211783893');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('39', '145729', '2021-02-27 00:00:00', '2021-03-11 00:00:00', 'Εκδόσεις στη κάτι απόλαυσε. Εκδόσεις δημιουργήσεις ωραίο τα ιδιαίτερα των. Μετράει επεξεργασία στα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('40', '1205629596', '2204883907');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('40', '106347', '2021-05-06 00:00:00', '2021-06-04 00:00:00', 'Εξοργιστικά μιας τρόπο νιρβάνα αγοράζοντας δυστυχώς εκδόσεις. Παράδειγμα οι ταξινομεί τρέξει συγγραφής. Αρχεία εδώ ρωτήσει γέλασαν έστελνε.', 'Γράψει προσπαθούν μου απόλαυσε. Έρθει ήδη ανώδυνη αρπάζεις χρειάζονται.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('41', '1505574288', '2807755832');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('41', '132359', '2023-02-09 00:00:00', '2023-03-06 00:00:00', 'Ανεπιθύμητη δείξει τη προγραμματιστής γεύματος γραμμής βάζοντας διορθώσει. Πάντως κανείς ανά άλγεβρα. Διάσημα νέο εργασίας άρα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('42', '1501611605', '1707129429');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('42', '8913', '2023-12-30 00:00:00', '2024-01-21 00:00:00', 'Στη ελέγχου ως συγχωνευτεί εργασίας. Συγγραφείς μας χρησιμοποιώντας παράγοντες.', 'Για περισσότερη μεταφραστής δοκιμάσεις περιβάλλον εσωτερικών βασανίζουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('43', '2101937959', '0511581912');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('43', '109355', '2025-03-03 00:00:00', '2025-03-04 00:00:00', 'Αποκλειστικούς προσπαθήσεις έτοιμος μου της δωροδοκηθούν μερικούς. Διασφαλίζεται επιδιόρθωση ταξινομεί προσπαθούν προσοχή.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('44', '2506000986', '0101856183');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('44', '100387', '2023-11-04 00:00:00', '2023-12-08 00:00:00', 'Σε αυτός ίδιο μας θα αποκλειστικούς. Χρειάζονται λες μάθε έτοιμος. Έχω και με τι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('45', '0605763265', '2811520835');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('45', '117767', '2024-06-22 00:00:00', '2024-07-21 00:00:00', 'Δύο ο εξαρτάται δεν. Τις δε μην σε νόμιζες κοιτάζοντας.', 'Από των παράγοντες πάντως.');
