INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('46', '52796', '2023-05-12 00:00:00', '2023-07-03 00:00:00', 'Απίστευτα αναγκάζονται ορίστε και. Μάθε διαχειριστής δυστυχής πάρεις ευκολότερο από. Την τον είχαμε ναι μάθε προγραμματιστές παράγοντες.', 'Πόρτες των ευκολότερο ίδιο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('47', '1106837316', '2209179097');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('47', '14838', '2020-10-23 00:00:00', '2020-12-09 00:00:00', 'Για αυτός αν όχι στη υόρκη εκτελέσει τη. Καταλάθος που εκτελέσεις κρατήσουν ας.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('48', '2810674122', '0510561691');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('48', '62698', '2025-12-19 00:00:00', '2026-01-16 00:00:00', 'Εσωτερικών διευθυντές πετούν χαμηλός πες συνάδελφος δύο ποσοστό. Εκθέσεις πάρα έλεγχος εργαλείων μετρήσεις φαινόμενο έρθει. Τρέξει τύπους επιστρέφουν.', 'Δε άλγεβρα ένας. Δυστυχής δύο τρέξει εδώ επενδυτής να.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('49', '0112766884', '0108820596');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('49', '87315', '2021-05-16 00:00:00', '2021-06-12 00:00:00', 'Χώρου εκτελείται πήρε επί διασφαλίζεται κλπ. Ίδιο άρα διορθώσεις πάντα πιο. Αντιλήφθηκαν αρχεία χρόνου εγώ αυτός δούλευε.', 'Πολύ συνέχεια ο περιεχόμενα διορθώσει σε πολύ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('50', '0312482341', '0609687829');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('50', '137082', '2023-07-16 00:00:00', '2023-08-14 00:00:00', 'Ώρα εντολές άτομο αυτήν γράψει ερωτήσεις ίδιο. Στο χαρτιού εγώ γραφικά την ποια μας για. Δεν πάντως σίγουρος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('51', '0502720704', '0308447051');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('51', '146334', '2025-05-13 00:00:00', '2025-07-02 00:00:00', 'Σίγουρος παραδώσεις που θέματα. Περισσότερη για γραμμή. Παραπάνω ακούσει έστελνε ναι απίστευτα. Δωροδοκηθούν χρονοδιαγράμματος από ήδη.', 'Τα από συγκεντρωμένοι συγγραφής πετάνε διάβασε κλπ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('52', '0703455993', '3012928959');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('52', '42137', '2026-09-03 00:00:00', '2026-10-28 00:00:00', 'Σας στραβά ευκολότερο αρέσει. Περιβάλλον προβληματική προκαλείς συνεχώς που προϊόντα δε. Μη δε χαρτιού μετρήσεις ποια απαράδεκτη μάτσο.', 'Στη προϊόντα συνέχεια αρέσει πάντα απαραίτητο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('53', '2604429081', '0402475992');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('53', '131687', '2022-11-03 00:00:00', '2022-11-19 00:00:00', 'Έτοιμος τι στήλες επιδιόρθωση ώρα. Έρθει επιδιόρθωση γειτονιάς αν εγώ κι σου ιδιαίτερα. Τύπου μέχρι αποστηθίσει την θυμάμαι ναι.
