INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('54', '57199', '2022-01-13 00:00:00', '2022-03-10 00:00:00', 'Συνεχώς εταιρείες κρατάει όταν δε στις. Παίρνει εξακολουθεί δεδομένων επενδυτής μάθε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('55', '0202665822', '3007734746');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('55', '64634', '2023-02-13 00:00:00', '2023-03-08 00:00:00', 'Προσεκτικά την πεδία επιδιορθώσεις βρίσκονται κι θέλεις. Ερωτήσεις τι της ιδιαίτερα επιστρέφουν πάντα ωραίο. Ροή χαρακτηριστικών μέχρι βασανίζουν.', 'Παίρνουν έγραψες ύψος ίδιο εξακολουθεί καταλάθος μέχρι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('56', '2604429081', '3004601620');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('56', '123493', '2022-07-08 00:00:00', '2022-09-02 00:00:00', 'Μη εκτελείται έτσι του προϊόντα χρησιμοποιούσες ωραίο. Σχεδιαστής έρθει έγραψες έρθει μια προκαλείς βαθμό. Προσοχή δύο νέο. Έγραψες πακέτων νέο θέμα τι κοιτάζοντας πως.', 'Ποια σε χρησιμοποιώντας έτσι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('57', '1706483980', '0408151010');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('57', '10345', '2020-12-21 00:00:00', '2021-01-14 00:00:00', 'Του τρόποι εξαρτάται σταματάς ανταγωνιστής. Προβληματική ίδιο οι κόψεις. Ήδη ως συνεχώς κώδικάς εκδόσεις προγραμματιστές μηχανής.', 'Δούλευε πάντα χρόνου χρόνου του.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('58', '0502720704', '2805518042');
