INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('59', '57690', '2023-04-29 00:00:00', '2023-05-09 00:00:00', 'Διαχειριστής πήρε πεδία διορθώσει είχαμε πες δημιουργείς. Διαδίκτυο της βασανίζουν ροή δεν. Επιχείριση εργαζόμενοι το πετούν στα δείξει. Ας σαν χρονοδιαγράμματα μαγικά που μάλλον έχω.', 'Κάνε τέλειοι νόμιζες βουτήξουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('60', '1706483980', '2603503057');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('60', '80738', '2024-06-30 00:00:00', '2024-08-02 00:00:00', 'Λιγότερο για όταν συνηθίζουν παραδώσεις ανακλύψεις. Μου επί μη άπειρα συγκεντρωμένοι εκτός μια. Θα ναι ταξινομεί εκτός.', 'Μου τελειώσει ναι διορθώσει ιδιαίτερα συγγραφείς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('61', '0109830948', '1905920014');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('61', '59473', '2025-10-24 00:00:00', '2025-11-26 00:00:00', 'Χαμηλός επί αντιλήφθηκαν την σου περιμένουν γραφικά συνεχώς. Ποσοστό θα για.', 'Φράση κώδικάς εγώ γιαυτό. Στα μεταγλωτίσει παίρνουν οι ήδη μιας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('62', '3112846972', '1610064691');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('62', '100541', '2023-09-21 00:00:00', '2023-11-13 00:00:00', 'Τους κάτι μέρος άλγεβρα ότι έχω μερικούς συνεχώς. Αναφέρονται χαρακτηριστικό ρωτήσει χρονοδιαγράμματα. Τύπους την πιο εξαρτάται αρέσει.
