INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('71', '27765', '2023-10-11 00:00:00', '2023-10-19 00:00:00', 'Αποθηκευτικού επενδυτής συγκεντρωμένοι τα. Σας λέει αυτήν και επί ας μη. Απαραίτητο έστελνε κάνε μη.', 'Χρειάζονται προκαλείς εφαμοργής γειτονιάς έρθει τα κάτι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('72', '1405971038', '1612042816');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('72', '144655', '2024-04-04 00:00:00', '2024-05-31 00:00:00', 'Εργαλείων ταξινομεί άλγεβρα. Σημαντικό παράγοντες αναφέρονται δημιουργήσεις μας.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('73', '1606531841', '2506648288');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('73', '14167', '2021-06-24 00:00:00', '2021-07-05 00:00:00', 'Άτομο έξι εργαλείων δουλεύει. Χώρου ναι πως εργαζόμενοι λοιπόν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('74', '1908859928', '1312466774');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('74', '119295', '2026-12-19 00:00:00', '2027-01-29 00:00:00', 'Δύο δούλευε περιεχόμενα σημεία πιο αποδείξεις κάτι τα. Πλέον μας αυτήν της άτομο επιδιόρθωση. Στις θέμα αυτήν πρώτοι.', 'Πετούν περιμένουν είχαμε ύψος χαρτιού όχι νιρβάνα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('75', '0202665822', '2812217455');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('75', '140039', '2020-09-20 00:00:00', '2020-10-16 00:00:00', 'Ανεπιθύμητη νόμιζες έχω. Την από εκείνου πιο. Να όταν τι πλέον εγώ μιας στο.', 'Μέχρι νιρβάνα βιβλίο διοικητικό θέματα αναγκάζονται.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('76', '1701895008', '1508843055');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('76', '128163', '2023-05-27 00:00:00', '2023-07-24 00:00:00', 'Χρησιμοποιώντας τρόπο δύο δεδομένων κάτι δυστυχής δεν. Γέλασαν ευκολότερο μη κάτι κώδικα άτομο συνέχεια. Μπουν φράση κάτι.', 'Στο διολισθήσεις επιδιόρθωση θέλεις σημεία εργάστηκε που.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('77', '1106837316', '2709124271');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('77', '131275', '2021-12-14 00:00:00', '2022-01-07 00:00:00', 'Διαδίκτυο πόρτες αυτός. Κάτι εκτός που μετρήσεις εργαζόμενοι θα σωστά. Έτσι πιο αποστηθίσει διολισθήσεις.', 'Ως μέρος ανταγωνιστής ναι κόψεις άλγεβρα εγώ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('78', '2002818500', '0103962811');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('78', '108110', '2026-04-29 00:00:00', '2026-06-27 00:00:00', 'Συγκεντρωμένοι γραφικά ρωτάει προσλάμβανες επί. Γεύματος λέει εσωτερικών και αυτήν. Απίστευτα πιο πακέτων μα ποια σαν υψηλότερη. Μας την κόλπα λαμβάνουν ανά τελειώσει ερωτήσεις.', 'Όχι δυστυχής πήρε φακέλους ταξινομεί. Σημεία δεν εγώ τύπου.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('79', '0603834902', '1709104543');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('79', '93087', '2022-05-31 00:00:00', '2022-07-06 00:00:00', 'Γεύματος τους των σταματάς αλγόριθμου είχαμε. Εταιρείες πετούν πιο παράγοντες προσπαθούν νόμιζες γέλασαν. Μετράει όσο κανόνα των ζητήσεις θέλεις ποια.', 'Μάλλον λετπά έτσι πλέον ποσοστό προκαλείς κι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('80', '0603834902', '1604980123');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('80', '2153', '2021-08-21 00:00:00', '2021-10-15 00:00:00', 'Ανταγωνιστής χρειάζονται με πολύ λοιπόν παραδοτέου κώδικάς. Διάβασε όταν έστειλε τι πετάνε. Χρειάζονται κι συνεχώς αθόρυβες μη τύπου νέων.', 'Σίγουρος λαμβάνουν ο ποια κειμένων μη περιμένουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('81', '1003762224', '1910138591');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('81', '37100', '2024-01-11 00:00:00', '2024-02-20 00:00:00', 'Στέλνοντάς ναι στη τη πετάξαμε όσο. Πλέον μη την δεν ελέγχου βιαστικά ένα. Απαραίτητο των χρόνου ένα διάσημα ανά.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('82', '3112846972', '0905613671');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('82', '11338', '2020-04-24 00:00:00', '2020-05-11 00:00:00', 'Μάλλον εξοργιστικά οι κάνεις δεν βουτήξουν δεν. Που μέσης κάτι. Μπορούσες χρονοδιαγράμματα ένα λες έξι έστειλε αφήσεις.', 'Πρώτο σου νόμιζες εκείνου δεν. Κάτι με κρατάει συνέχεια πολύ διολισθήσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('83', '1701895008', '0709653879');
