INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('85', '104332', '2024-03-30 00:00:00', '2024-04-11 00:00:00', 'Ανεπιθύμητη τοπικές μεταφραστής στη τις πάντα ποια. Πετούν τρόπο σαν σας περισσότερη δημιουργήσεις.', 'Γιαυτό δωροδοκηθούν ρωτάει θα.');
