INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('86', '40914', '2021-08-28 00:00:00', '2021-09-29 00:00:00', 'Τέλειοι αποδείξεις μα ανώδυνη πως αφήσεις. Λοιπόν κρατήσουν εγώ εσωτερικών λιγότερο παίρνει τρόποι μπουν. Ποια βγήκε ανά τρόπο ρωτήσει βαθμό τα.', 'Εσωτερικών τα κι. Περιβάλλον στο κανόνα κειμένων κειμένων περισσότερη.');
