INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('103', '68673', '2021-09-12 00:00:00', '2021-10-08 00:00:00', 'Περιβάλλον ωραίο ας αποστηθίσει σας περισσότερη κι στραβά. Ποια ως εδώ επί υποψήφιο που θα.', 'Κι νόμιζες πετούν περίπου. Προκαλείς καλύτερο πόρτες μια τέλειοι γιαυτό.');
