INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('122', '2512851383', '1506010161');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('122', '25411', '2020-12-20 00:00:00', '2021-01-16 00:00:00', 'Άλγεβρα πιο ένας οι απαραίτητο νόμιζες ένα. Τους θέλεις παράδειγμα αποθηκευτικού μέχρι εργάστηκε τα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('123', '0411993833', '2506648288');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('123', '138793', '2024-06-28 00:00:00', '2024-07-21 00:00:00', 'Κώδικάς ίδιο αφήσεις οι. Οι επιστρέφουν βγήκε αντιλήφθηκαν. Χειρότερα καλύτερο κανένας επί μέρος. Αποκλειστικούς εργαλείων νόμιζες έλεγχος τα γνωρίζουμε.', 'Χρονοδιαγράμματος κάνε πάρα. Ρουτίνα άλγεβρα σημαντικό παίρνει έξι θέλεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('124', '2507471459', '1206721109');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('124', '129288', '2020-08-06 00:00:00', '2020-09-09 00:00:00', 'Των ζητήσεις ναι γειτονιάς δημιουργήσεις γνωρίζουμε. Αν εκείνου χώρου δημιουργείς αγοράζοντας ακούσει. Ιδιαίτερα από έτσι γεγονός εφαρμογή διολισθήσεις.', 'Πλέον έλεγχος συγγραφείς εργοστασίου το θέματα για σημαντικό.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('125', '0509833294', '0504028402');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('125', '88865', '2022-10-02 00:00:00', '2022-11-30 00:00:00', 'Διευθυντές βρίσκονται τελειώσει σπίτι. Διάσημα σημαντικός μην παράδειγμα άτομο. Έστειλε δεν μην κώδικάς.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('126', '2305001120', '1603433260');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('126', '58585', '2021-04-12 00:00:00', '2021-05-04 00:00:00', 'Ανά πετάξαμε έτσι χαρακτηριστικό άρθρων. Γραφικά αποθηκευτικού εξοργιστικά απαράδεκτη υποψήφιο προγραμματιστής. Ίδιο χρησιμοποιούσες σωστά στις τύπου προσοχή.', 'Έτσι βουτήξουν τα θα κανόνα συνάδελφος ποια βρίσκονται.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('127', '2207939324', '2208596180');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('127', '86645', '2026-02-16 00:00:00', '2026-04-15 00:00:00', 'Και τέλειοι περίπου των. Αυτήν νέου απίστευτα λετπά διαφήμιση.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('128', '2310469829', '1312466774');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('128', '82003', '2025-12-18 00:00:00', '2025-12-21 00:00:00', 'Ποια έστειλε μου σημαντικός εταιρείες δημιουργείς. Που έξι κανόνα πετάνε. Ναι ως δοκιμάσεις μεταφραστής ήδη.', 'Προσλάμβανες επί γραμμής διάσημα διοικητικό για μπουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('129', '2305001120', '1105475121');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('129', '113136', '2023-06-14 00:00:00', '2023-07-10 00:00:00', 'Πάντως διοικητικό κρατήσουν συγχωνευτεί δημιουργήσεις προϊόντα.', 'Υψηλότερη σπίτι βαθμό δε. Κειμένων στις μια εντολές προκαλείς ένα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('130', '0705997672', '3007734746');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('130', '109730', '2025-05-29 00:00:00', '2025-05-31 00:00:00', 'Στραβά προσοχή γραμμής τι. Απαραίτητο των προσεκτικά ορίστε.', 'Τύπους τη χρειάζονται ζητήσεις. Θέμα απομόνωση δυστυχώς ταξινομεί ερωτήσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('131', '1406967967', '0511711784');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('131', '53343', '2025-02-11 00:00:00', '2025-02-18 00:00:00', 'Κάτι εφαρμογή νέο νέων γνωστή μας που. Περισσότερες μέγιστη τους μέρος έστειλε ότι μια.', 'Χαρακτηριστικό ζητήσεις απαραίτητο ότι εκείνου εργάστηκε άρα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('132', '1812640874', '2801010104');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('132', '134666', '2022-04-07 00:00:00', '2022-04-20 00:00:00', 'Πως ανταγωνιστής από που απαράδεκτη στέλνοντάς έλεγχος με. Απίστευτα μου πλέον διαδίκτυο χρειάζονται μιας. Κανόνα τοπικές τρόπο εντολές στο πλέον ο.', 'Τι μαγικά χρονοδιαγράμματα πλέον διακόψουμε μεταγλωτίσει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('133', '0605763265', '0903967701');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('133', '49212', '2026-12-31 00:00:00', '2027-02-02 00:00:00', 'Τους περισσότερες συγγραφής πιο αναφέρονται. Μας αρχεία εξακολουθεί νιρβάνα. Μην δημιουργια θέματα ότι αν λέει εφαμοργής.', 'Εκτελέσει εφαρμογή βγήκε χρονοδιαγράμματα προσπαθήσεις έγραψες αναφέρονται.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('134', '0307516056', '2110730914');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('134', '69824', '2026-06-05 00:00:00', '2026-06-27 00:00:00', 'Δύο εκθέσεις διολισθήσεις ποσοστό.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('135', '1701895008', '1802025805');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('135', '109067', '2026-09-21 00:00:00', '2026-10-09 00:00:00', 'Στήλες λοιπόν άρθρων τρόποι ο. Λοιπόν μάτσο πρώτο γραμμή δημιουργείς πως εργασίας. Παράγοντες τους συνεντεύξεις ιδιαίτερα σας.', 'Σε σαν πεδία από για εργαζόμενων. Διολισθήσεις θα προγραμματιστές.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('136', '2811680880', '1810565829');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('136', '90585', '2022-03-31 00:00:00', '2022-05-04 00:00:00', 'Αναφέρονται εκτελέσεις οι μέσης. Συγχωνευτεί δεν έχω και σου εργασίας κλπ ημέρα. Στήλες δε πάρεις δύο περισσότερες έχω. Ειδικά που εκτός παίξουν τους γραφικά.', 'Εφαρμογή τι τελειώσει σου ορίστε. Έστελνε λέει που το πόρτες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('137', '3112988719', '2701095374');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('137', '37587', '2021-09-20 00:00:00', '2021-10-04 00:00:00', 'Του από γραμμές κι πάντα. Μην άτομο εκτός φράση.', 'Πηγαίου μα μεταγλωτίσει επιστρέφουν σχεδιαστής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('138', '2107478266', '0108927665');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('138', '55686', '2023-08-22 00:00:00', '2023-10-07 00:00:00', 'Άρθρων περιεχόμενα εγώ μιας. Ένα γράψει πάρεις ιδιαίτερα κάτι μέχρι. Λετπά σε νέων γραμμές παραγωγικής ιδιαίτερα κάνε.', 'Για εκδόσεις το έστειλε ποσοστό πετάνε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('139', '0803462007', '1207710361');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('139', '90906', '2026-08-15 00:00:00', '2026-10-04 00:00:00', 'Διαδίκτυο στα στα για έλεγχος αποκλειστικούς. Προσθέσει ευκολότερο σαν τα. Εξοργιστικά ότι σημαντικός από διαδίκτυο.', 'Άπειρα κάτι εκδόσεις πόρτες μου πάντως.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('140', '1106837316', '0506419341');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('140', '101636', '2026-04-27 00:00:00', '2026-05-09 00:00:00', 'Εντολές απομόνωση μερικούς μέρος βουτήξουν. Δωροδοκηθούν μας επιχείριση περιβάλλον.
