INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('141', '25302', '2023-01-12 00:00:00', '2023-01-18 00:00:00', 'Διολισθήσεις τοπικές πάντα χρονοδιαγράμματα έξι ίδιο σχεδιαστής. Που προκύπτουν σπίτι διολισθήσεις. Έστειλε βάζοντας φράση παραπάνω του.', 'Προγραμματιστής έτοιμος στα επιχείριση που. Το μια εδώ. Κλπ που μην ατόμου.');
