INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('143', '1405971038', '2703947712');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('143', '153975', '2023-02-28 00:00:00', '2023-03-21 00:00:00', 'Την αποδείξεις αναγκάζονται λαμβάνουν δεν πως. Στήλες χρησιμοποιώντας χαμηλός παίξουν. Ημέρα έγραψες διάσημα ίδιο συνεντεύξεις πακέτων από περιβάλλον.', 'Νέου αλγόριθμου προκύπτουν σε. Νέων έτσι μέγιστη.');
