INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('145', '2608633605', '2502072553');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('145', '107393', '2022-03-05 00:00:00', '2022-04-30 00:00:00', 'Βάζοντας καταλάθος δείξει μεταγλωτίσει ας προσοχή έτσι. Την επί ανώδυνη παίξουν κώδικάς κρατάει κανόνα.', 'Δεν ερώτηση στήλες κόψεις σου. Κάτι συγκεντρωμένοι λετπά ένα αυτός καλύτερο.');
