INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('147', '102428', '2021-01-10 00:00:00', '2021-02-05 00:00:00', 'Έξι σου να μέσης. Κρατάει συγχρόνως οι μέχρι γραφικά το καλύτερο. Άλγεβρα μετρήσεις μέχρι μιας τη δημιουργια. Αν διακόψουμε ακούσει αλγόριθμου ταξινομεί σου.', 'Από θέμα εκτός. Εκδόσεις χρησιμοποίησέ λίγο δε σχεδιαστής αφήσεις μάθε.');
