INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('149', '0110417536', '0612434890');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('149', '5142', '2025-07-16 00:00:00', '2025-08-15 00:00:00', 'Παράδειγμα τα δύο δημιουργήσεις εφαρμογής νέου έστελνε σημεία. Δεν τη απομόνωση τις. Δυστυχώς συγκεντρωμένοι βαθμό. Προβληματική υποψήφιο προσεκτικά μη σχεδιαστής πιο για.', 'Γραμμή στο άρθρων δουλεύει θα εργαζόμενων.');
