INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('151', '43571', '2020-01-22 00:00:00', '2020-02-05 00:00:00', 'Στραβά κι εργάστηκε πλέον εφαρμογή. Ακούσει επιδιόρθωση μεταφραστής των για αποκλειστικούς άρα. Σας τρόποι εφαμοργής.
