INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('153', '1012868287', '1505550252');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('153', '133038', '2023-09-25 00:00:00', '2023-11-14 00:00:00', 'Εικόνες δεν παραδοτέου κάτι μέχρι. Νέα δωροδοκηθούν τρόποι μετρήσεις τύπου.', 'Διάβασε διασφαλίζεται ένα εργασίας οι γέλασαν θέματα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('154', '1210537343', '2506405612');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('154', '99500', '2022-04-15 00:00:00', '2022-06-05 00:00:00', 'Φακέλους ποια μιας πιο. Πολύ εδώ πολύ τρέξει πρώτης αγοράζοντας κάτι από. Λίγο πάντως στα σαν βρίσκονται χρονοδιαγράμματα ναι. Είχαμε τη πως έλεγχος ορίστε κόψεις τις.', 'Γράψει ήδη της γεύματος αποφάσισε ημέρα κανένας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('155', '2101937959', '1610064691');
