INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('157', '2204731625', '1207710361');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('157', '114470', '2020-02-03 00:00:00', '2020-02-12 00:00:00', 'Στήλες θέμα σκεφτείς κανένας. Εδώ ότι καταλάθος προσλάμβανες άτομο κάτι λιγότερο. Τον εκτελέσεις τύπου ροή όσο κρατήσουν πολύ.', 'Πετάξαμε όσο χαρακτηριστικό μπορούσες που συγγραφείς ναι σημαντικός.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('158', '1908859928', '1207710361');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('158', '57701', '2021-08-15 00:00:00', '2021-09-09 00:00:00', 'Δυστυχώς παραδώσεις πετάνε διορθώσεις πιο και προσλάμβανες. Περιεχόμενα λέει κανόνα λίγο. Χρησιμοποιώντας χάος συνέχεια διάβασε.', 'Άπειρα μεταγλωτίσει ανά εκτός εικόνες φακέλους.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('159', '2002818500', '1809534511');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('159', '46415', '2021-10-11 00:00:00', '2021-10-27 00:00:00', 'Επί συγχρόνως χαρακτηριστικό μηχανής ως προσλάμβανες. Πάντως σημαντικός μια κάνεις γεύματος. Τρέξει σωστά διακοπή ναι αυτός απίστευτα προσπαθούν. Χρόνου περιμένουν τύπους αποκλειστικούς.', 'Εδώ της μου. Διορθώσεις αλγόριθμου ρωτήσει ποια μηχανής τις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('160', '2702666773', '0201768300');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('160', '136770', '2023-03-30 00:00:00', '2023-04-29 00:00:00', 'Γέλασαν τα ένας εργαζόμενων νέου αναγκάζονται ανά. Σχεδιαστής πολύ μας ως.', 'Χρησιμοποιούνταν δύο και. Μέχρι δεν επεξεργασία πιο εκθέσεις μιας επιστρέφουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('161', '0109830948', '1109084448');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('161', '737', '2024-04-21 00:00:00', '2024-06-07 00:00:00', 'Μετρήσεις προσπαθήσεις τι εργαλείων περιεχόμενα την εντολές. Εκτελείται μας παίρνει άρα. Εξακολουθεί τρόπο ταξινομεί πες τεσσαρών επί ήδη.', 'Γέλασαν πετάξαμε δωροδοκηθούν μεταγλωτιστής μέχρι διακοπή ωραίο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('162', '2408976407', '2805627622');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('162', '28354', '2020-06-07 00:00:00', '2020-08-05 00:00:00', 'Πλέον όταν βασανίζουν ξέχασε πάντα. Εργάστηκε εργαζόμενων που. Αυτήν χρειάζονται μα προσεκτικά των.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('163', '2807932946', '0809691857');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('163', '96313', '2023-11-28 00:00:00', '2024-01-09 00:00:00', 'Ορίστε διασφαλίζεται δε απόλαυσε δουλεύει έτσι αναφορά ύψος. Τη παραπάνω εκτελείται κανόνα προγραμματιστής. Κανόνα απλό μιας βασανίζουν λες όταν δεν.', 'Συγγραφής στήλες πάντα έτσι. Σωστά φίλος χαρακτηριστικό ο φακέλους.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('164', '1106837316', '3012147407');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('164', '56731', '2024-07-29 00:00:00', '2024-08-19 00:00:00', 'Σημαντικό λετπά κι κώδικάς ωραίο. Πρώτο εξακολουθεί του χαρακτηριστικό ζητήσεις άτομο. Εκθέσεις νόμιζες μη που δεδομένων δωροδοκηθούν στέλνοντάς χρονοδιαγράμματος.', 'Πάρα μην παραπάνω απαραίτητο ήδη έτοιμος. Ποια νιρβάνα έτοιμος έστειλε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('165', '2207939324', '1109084448');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('165', '74573', '2026-09-07 00:00:00', '2026-10-09 00:00:00', 'Είχαμε δύο εξαρτάται μου. Μια λίγο επιστρέφουν σου διάβασε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('166', '2506000986', '1802025805');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('166', '26106', '2023-02-10 00:00:00', '2023-03-21 00:00:00', 'Χαρτιού κάτι εκτός προσεκτικά γειτονιάς σε. Άρα χαρακτηριστικών περιβάλλον τα μη ποια ατόμου.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('167', '2807932946', '2009932681');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('167', '26053', '2025-10-11 00:00:00', '2025-11-06 00:00:00', 'Ρωτάει μας ροή έχω. Κι περιβάλλοντος πάντα εσωτερικών. Αποδείξεις για φίλος έχω ύψος.', 'Δημιουργια προσοχή εκτός παίρνουν που στο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('168', '1012868287', '3007896243');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('168', '96930', '2021-05-18 00:00:00', '2021-05-31 00:00:00', 'Δε ταξινομεί διαπιστώνεις σε συγχωνευτεί. Χρονοδιαγράμματος διακοπής ώρα διευθυντές ταξινομεί νιρβάνα κάνεις χειρότερα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('169', '0110417536', '2709198210');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('169', '61438', '2024-11-04 00:00:00', '2025-01-02 00:00:00', 'Πήρε σημαντικός στη τα στις προσοχή γειτονιάς ερωτήσεις. Εργαζόμενων εκτός τύπους τα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('170', '2506000986', '2205191621');
