INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('171', '2506000986', '0811689180');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('171', '73577', '2021-12-03 00:00:00', '2022-01-07 00:00:00', 'Του ρωτάει τις σημεία εξακολουθεί. Δεν των αν επί εσωτερικών ήδη κάνε. Δοκιμάσεις μέρος κι μα παραπάνω ανά.', 'Στις παραπάνω στις όσο παράγοντες μερικούς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('172', '0603834902', '0811689180');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('172', '98183', '2021-09-23 00:00:00', '2021-10-02 00:00:00', 'Σημαντικό ελέγχου ειδικά προγραμματιστές ας. Αν ξέχασε μεταφραστής έτσι ερώτηση ανταγωνιστής που πόρτες. Γραμμής κειμένων μερικούς ανεπιθύμητη συγχρόνως αναφέρονται.', 'Αντιλήφθηκαν αρχεία σας μέχρι ρωτάει ίδιο επιδιορθώσεις. Αποστηθίσει κόψεις κι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('173', '0905718925', '1101696467');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('173', '44529', '2025-12-17 00:00:00', '2026-02-14 00:00:00', 'Εκτός ήδη αρέσει πηγαίου πιο εργαζόμενοι. Διολισθήσεις ας πηγαίου όχι. Μην στραβά ρωτήσει πήρε μετρήσεις στα.', 'Αποκλειστικούς χρησιμοποίησέ πάρεις απαράδεκτη δύο εξακολουθεί.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('174', '2604429081', '1612042816');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('174', '96038', '2025-03-02 00:00:00', '2025-03-24 00:00:00', 'Πρώτοι κάνε μας χρόνου ανταγωνιστής λιγότερο διάσημα. Χρονοδιαγράμματα συνεντεύξεις πάντα τρόπο ναι των κάτι αλγόριθμου.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('175', '2310469829', '0609687829');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('175', '86561', '2021-10-29 00:00:00', '2021-11-25 00:00:00', 'Θέλεις ανά πάντως του χρησιμοποίησέ. Διαχειριστής σε σημαντικό βιβλίο τι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('176', '1706483980', '2104236019');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('176', '98126', '2024-04-02 00:00:00', '2024-05-24 00:00:00', 'Τις νέου λιγότερο διαπιστώνεις ότι στα περισσότερη. Παραδώσεις νέων υπηρεσία όχι σκεφτείς γραμμές. Ρωτάει εργαζόμενων χάος εγώ μπορούσες εγώ.', 'Κοιτάζοντας ο προγραμματιστής αν τις πετούν παράδειγμα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('177', '0112766884', '1604980123');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('177', '60615', '2026-06-15 00:00:00', '2026-07-14 00:00:00', 'Τέλειοι ποια μεταγλωτίσει. Απαράδεκτη της εκτός δε δύο κώδικα. Ημέρα στα μάθε πετάξαμε προϊόντα κανένας.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('178', '3112425377', '0402475992');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('178', '131101', '2024-01-11 00:00:00', '2024-02-13 00:00:00', 'Προϊόντα πλέον άρα. Του μεταγλωτίσει εκτός ελέγχου διαπιστώνεις περιβάλλοντος κρατήσουν.', 'Εγώ νέων δημιουργια σαν των δύο στήλες. Σαν παραδώσεις οι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('179', '2310497857', '1103598182');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('179', '55865', '2022-08-15 00:00:00', '2022-10-07 00:00:00', 'Να έρθει έλεγχος νέο. Μπορούσες άτομο στη διολισθήσεις ως διαφήμιση ρωτήσει. Προκύπτουν δουλεύει ήδη χρειάζονται χρησιμοποίησέ. Βουτήξουν ζητήσεις ορίστε εκτελείται στραβά δυστυχής γέλασαν κλπ.', 'Χαρακτηριστικών τον κόλπα θέμα τους τη. Και όταν χώρου βρίσκονται έλεγχος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('180', '0307516056', '0812660044');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('180', '102399', '2026-06-06 00:00:00', '2026-06-25 00:00:00', 'Περιεχόμενα γεγονός μου άρθρων συνάδελφος υψηλότερη διαδίκτυο πακέτων. Σταματάς προσοχή ώρα απαραίτητο κάνε ξέχασε ωραίο.', 'Εσωτερικών κι εσωτερικών αν. Βιαστικά προσλάμβανες ως μέχρι άτομο εφαρμογή ο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('181', '1205629596', '2011488718');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('181', '87607', '2025-02-08 00:00:00', '2025-02-11 00:00:00', 'Προσθέσει σου σχεδιαστής ρωτάει θυμάμαι δείξει προσπαθούν. Γραφικά άλγεβρα επιστρέφουν χρησιμοποιώντας. Διοικητικό ότι άπειρα λέει μαγικά χαμηλός αυτός.', 'Κι εγώ των πολύ. Απόλαυσε άρα περίπου εργαζόμενων.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('182', '0110417536', '2809900630');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('182', '105160', '2024-07-31 00:00:00', '2024-09-06 00:00:00', 'Εκτελείται άρθρων λιγότερο. Εκείνου διακοπής στη προσπαθούν εξακολουθεί. Να μάθε και γνωρίζουμε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('183', '0112766884', '1107031939');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('183', '114653', '2026-04-13 00:00:00', '2026-06-05 00:00:00', 'Διαδίκτυο λοιπόν και ανεπιθύμητη το σου. Χαρακτηριστικών για ακούσει έχω μια ας σπίτι. Πάντως για με ημέρα τοπικές μάτσο λοιπόν.', 'Ως ανώδυνη έλεγχος χαμηλός εξαρτάται ναι ρωτάει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('184', '0703455993', '0504028402');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('184', '36978', '2020-07-19 00:00:00', '2020-08-16 00:00:00', 'Επιστρέφουν αποθηκευτικού μα καλύτερο στα προκαλείς εσωτερικών. Εγώ χαρακτηριστικών εργάστηκε συνέχεια μιας πιο ανεπιθύμητη.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('185', '2207939324', '2603403988');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('185', '3322', '2020-06-10 00:00:00', '2020-07-21 00:00:00', 'Εκτός τοπικές βάζοντας λέει ώρα στη χώρου. Μέρος πάρεις έχω σίγουρος απαρατήρητο ελέγχου.
