INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('186', '130848', '2022-09-14 00:00:00', '2022-09-21 00:00:00', 'Έξι κρατήσουν πετούν σου περιβάλλον νιρβάνα. Χάος τις δημιουργείς συνέχεια όταν. Αναφορά προσοχή διακοπή την την.', 'Λαμβάνουν εντολές σας δε μη να ας αρπάζεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('187', '0502720704', '3005449525');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('187', '18998', '2023-01-11 00:00:00', '2023-01-29 00:00:00', 'Εταιρείες περιβάλλον τη ανακλύψεις εφαρμογής μέχρι. Δωροδοκηθούν μια αν εντολές.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('188', '1606531841', '1912081507');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('188', '38675', '2020-06-09 00:00:00', '2020-08-03 00:00:00', 'Έστειλε ας στέλνοντάς σπίτι ανώδυνη. Ναι τον ίδιο από πρόσληψη διευθυντές μην.', 'Ίδιο διορθώσεις έτοιμος των ατόμου πεδία.');
