INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('190', '3112425377', '2405776523');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('190', '56715', '2021-06-03 00:00:00', '2021-06-04 00:00:00', 'Σημαντικός αφήσεις πάντα συνηθίζουν μην κάτι απίστευτα πάντα. Δουλεύει βρίσκονται αναγκάζονται.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('191', '0202665822', '2104236019');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('191', '120538', '2022-06-30 00:00:00', '2022-07-07 00:00:00', 'Έχω κύκλο πιο προσθέσει προσπαθούν έχω. Δημιουργείς όσο αυτήν χώρου χαρακτηριστικό διασφαλίζεται συγχρόνως. Μας κώδικα καλύτερο κάτι μπορούσες αρέσει με.', 'Να αθόρυβες πήρε σκεφτείς. Επιδιορθώσεις μετρήσεις ακούσει στήλες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('192', '2604429081', '0701443276');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('192', '153452', '2021-03-30 00:00:00', '2021-05-12 00:00:00', 'Χάος τοπικές κώδικα. Τι μα της γνωστή επί θέμα. Είχαμε κι πες μερικούς.', 'Σε διάβασε ρουτίνα εργοστασίου περιμένουν σας μεταγλωτιστής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('193', '0703455993', '1508843055');
