INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('194', '1707411678', '0103962811');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('194', '126834', '2023-01-29 00:00:00', '2023-02-01 00:00:00', 'Τα πηγαίου των εξαρτάται όταν. Πετούν άρθρων συνέχεια δημιουργια κώδικάς πάρα τα. Πιο χαμηλός ειδικά αρχεία χρησιμοποιώντας.', 'Στέλνοντάς πλέον γεύματος. Δεν μετράει ναι τα λοιπόν πάντα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('195', '2807932946', '2902201793');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('195', '123126', '2023-08-08 00:00:00', '2023-09-23 00:00:00', 'Τη παράδειγμα την διακοπή εκείνου πλέον πρώτο. Για περιεχόμενα εξοργιστικά εξοργιστικά συνεντεύξεις. Από με εργοστασίου πλέον πιο.', 'Επενδυτής της που ως ανώδυνη νιρβάνα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('196', '2507471459', '1501743484');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('196', '136382', '2026-07-04 00:00:00', '2026-07-25 00:00:00', 'Συγκεντρωμένοι εξαρτάται ελέγχου της. Χρησιμοποιούσες σημεία τι ερωτήσεις διακοπής ποια διάβασε. Θέμα βασανίζουν ρουτίνα επεξεργασία κι δείξει δύο.', 'Επί εταιρείες αρχεία παράδειγμα μάλλον στήλες ανά.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('197', '1612469221', '0809691857');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('197', '38417', '2023-01-24 00:00:00', '2023-03-09 00:00:00', 'Κρατήσουν με επενδυτής έστειλε ροή.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('198', '2308667908', '2009932681');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('198', '1274', '2020-07-23 00:00:00', '2020-07-28 00:00:00', 'Όχι κάτι επιδιόρθωση να. Με των αλγόριθμου γιαυτό απλό περισσότερη γραφικά εργάστηκε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('199', '0110417536', '0803673981');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('199', '58061', '2024-11-14 00:00:00', '2024-12-01 00:00:00', 'Παίξουν ανεπιθύμητη στη φακέλους. Χρησιμοποιούνταν μα τα παραδώσεις απαρατήρητο τι τύπου. Τη τις εκτός εντολές δε.', 'Μια διορθώσεις και το ρουτίνα γράψει. Ένας δεδομένων τους εικόνες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('200', '0112784509', '1810995810');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('200', '123450', '2024-07-14 00:00:00', '2024-08-17 00:00:00', 'Να στις έχω χρησιμοποίησέ διολισθήσεις τεκμηριώνει σαν. Χρησιμοποιούσες ανώδυνη της μάθε διακόψουμε φίλος. Προσπαθήσεις τον τι ότι ρωτάει δύο είχαμε.', 'Αποφάσισε μην συγγραφείς πως ας. Διακοπής τα αποφάσισε εκδόσεις αγοράζοντας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('201', '0810507694', '0511581912');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('201', '157158', '2021-05-03 00:00:00', '2021-05-19 00:00:00', 'Πως για περισσότερη τρέξει ποια ήδη. Γνωρίζουμε αντιλήφθηκαν εσωτερικών δείξει αντιλήφθηκαν πάντα περισσότερη μας.', 'Το υψηλότερη διακοπής χαρακτηριστικών. Έτσι μιας οι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('202', '3107928009', '0812660044');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('202', '140307', '2023-08-23 00:00:00', '2023-10-22 00:00:00', 'Ανεπιθύμητη εκτός μετράει έξι στήλες πως πιο. Πάρα εντολές βιβλίο ναι. Όταν εγώ πρώτο χρησιμοποιούσες.', 'Τεσσαρών τις απομόνωση σας ήδη συγχρόνως πηγαίου.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('203', '0605763265', '1001533923');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('203', '158354', '2025-10-08 00:00:00', '2025-11-23 00:00:00', 'Τη λοιπόν σου ροή δωροδοκηθούν στέλνοντάς κώδικάς. Εντολές καλύτερο έστειλε ότι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('204', '1205629596', '3007734746');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('204', '20241', '2026-04-28 00:00:00', '2026-06-21 00:00:00', 'Μου ποσοστό εγώ κι συγχωνευτεί διαφήμιση προγραμματιστής. Στα άπειρα διαφήμιση ανακλύψεις διορθώσει. Συνηθίζουν αν ίδιο το επί χρόνου αποστηθίσει.', 'Εφαρμογή αγοράζοντας ο λίγο πλέον περισσότερη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('205', '2101937959', '2607201995');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('205', '38854', '2023-01-12 00:00:00', '2023-02-05 00:00:00', 'Ημέρα κόλπα κόλπα κανόνα μέχρι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('206', '1501611605', '2611784250');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('206', '160744', '2026-07-27 00:00:00', '2026-08-21 00:00:00', 'Ακούσει ένας δεν γέλασαν. Άρα χαρτιού και δεν γιαυτό κειμένων εγώ τα. Κάνε έτσι δεν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('207', '0312482341', '2603403988');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('207', '77916', '2023-11-05 00:00:00', '2023-11-08 00:00:00', 'Περισσότερες εκτελέσεις και συγγραφείς περιβάλλοντος δείξει εκτελέσει. Συνηθίζουν χαρακτηριστικών πιο κάνεις διασφαλίζεται.', 'Εργαζόμενων άλγεβρα έξι αρέσει σου μέσης στα την. Εφαμοργής στη λέει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('208', '0104945542', '0304180463');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('208', '113439', '2022-07-13 00:00:00', '2022-07-28 00:00:00', 'Τι δεδομένων απόλαυσε πάντως διασφαλίζεται εγώ επί βιβλίο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('209', '0502720704', '0707048882');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('209', '9199', '2021-11-25 00:00:00', '2021-12-08 00:00:00', 'Εφαρμογής διαπιστώνεις τις διαπιστώνεις. Ήδη από μέχρι επί μα εξακολουθεί μας. Εγώ υόρκη συγγραφείς χρειάζονται αποκλειστικούς δύο διολισθήσεις.', 'Ταξινομεί πρώτης φίλος προκαλείς κανένας διορθώσει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('210', '1003762224', '1802025805');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('210', '101846', '2026-02-25 00:00:00', '2026-04-16 00:00:00', 'Εσωτερικών πρώτοι ποια κλπ αποκλειστικούς. Συγκεντρωμένοι έλεγχος σου υπηρεσία μας που απαραίτητο. Μου απόλαυσε θέλεις περίπου χαρακτηριστικό.', 'Όταν συνέχεια ημέρα. Δυστυχής στη τρόπο προσθέσει μάλλον.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('211', '2705635938', '0108927665');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('211', '41046', '2020-01-08 00:00:00', '2020-02-14 00:00:00', 'Φίλος συγγραφείς έστειλε. Καταλάθος πάντα στήλες ωραίο ένα στις συγχρόνως αποφάσισε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('212', '0109830948', '1807814964');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('212', '91990', '2024-05-31 00:00:00', '2024-06-14 00:00:00', 'Πήρε τρέξει έστελνε βασανίζουν έτοιμος. Κι στη μη μη βρίσκονται χάος απομόνωση τελειώσει.', 'Τι δυστυχώς νέα νιρβάνα χρησιμοποίησέ μια νόμιζες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('213', '0905718925', '2208596180');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('213', '12568', '2020-10-04 00:00:00', '2020-11-07 00:00:00', 'Ας αθόρυβες πακέτων ρωτήσει. Χρόνου ήδη πως εξοργιστικά διορθώσεις του. Άρα απαράδεκτη ξέχασε εγώ κώδικάς χρησιμοποίησέ επενδυτής του.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('214', '2805925031', '1402610255');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('214', '10852', '2020-10-29 00:00:00', '2020-12-20 00:00:00', 'Σαν κι οι δε. Σκεφτείς για αφήσεις ότι ευκολότερο κρατήσουν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('215', '1205629596', '1802025805');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('215', '47770', '2026-08-01 00:00:00', '2026-09-15 00:00:00', 'Πρώτο προκαλείς γραφικά ένα καλύτερο ωραίο. Στέλνοντάς ίδιο ναι βουτήξουν που γραμμή ξέχασε. Μετρήσεις ροή εδώ εργαζόμενοι μπορούσες βγήκε.', 'Επί σου στα εφαμοργής ωραίο τύπους.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('216', '1205629596', '0201768300');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('216', '94656', '2023-08-25 00:00:00', '2023-10-05 00:00:00', 'Δύο τις ποια μηχανής. Τεκμηριώνει γραμμή είχαμε από. Πρώτο εδώ τις προκαλείς τι. Τη περισσότερες πεδία υόρκη σαν παράδειγμα.', 'Υπηρεσία συγχωνευτεί το. Μέχρι σου ποια ως διαδίκτυο έξι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('217', '2711519870', '2611910254');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('217', '85456', '2025-06-03 00:00:00', '2025-07-26 00:00:00', 'Αγοράζοντας ευκολότερο εκτός σίγουρος τεσσαρών. Αθόρυβες παραδώσεις ανώδυνη. Λαμβάνουν χρησιμοποιώντας εφαρμογής διαπιστώνεις ώρα μας επιδιορθώσεις ένας.', 'Πρώτης βγήκε ύψος πάρα γραφικά. Το κύκλο διορθώσεις την.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('218', '1908859928', '2208596180');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('218', '105403', '2020-04-14 00:00:00', '2020-05-28 00:00:00', 'Μας τη τη λες κανένας. Όταν όσο φαινόμενο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('219', '2702666773', '2506648288');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('219', '81751', '2025-02-25 00:00:00', '2025-03-04 00:00:00', 'Νόμιζες κώδικα στη ίδιο σταματάς λαμβάνουν. Πετάνε άρα δημιουργια έγραψες αποδείξεις ευκολότερο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('220', '2101937959', '1705630094');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('220', '21387', '2026-10-11 00:00:00', '2026-11-26 00:00:00', 'Ας αναφορά που αφήσεις χρονοδιαγράμματα διευθυντές. Ύψος ανταγωνιστής του εργασίας ανεπιθύμητη χαμηλός.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('221', '0810507694', '0310049988');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('221', '116425', '2026-12-15 00:00:00', '2026-12-19 00:00:00', 'Δεδομένων απομόνωση πες συγχωνευτεί πολύ τις προβληματική μάτσο. Λίγο πολύ δημιουργια προγραμματιστές ειδικά.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('222', '1902811264', '1802025805');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('222', '34288', '2022-03-14 00:00:00', '2022-03-17 00:00:00', 'Μην ένας πετούν στήλες εργαλείων στη στέλνοντάς. Συγχωνευτεί ανά εγώ απαραίτητο έξι μηχανής κρατάει. Περιβάλλοντος σημαντικός γράψει διαφήμιση χαρακτηριστικών τρέξει αθόρυβες.', 'Εκείνου αν εξαρτάται δοκιμάσεις. Πιο κάνε κάτι των διακοπή πάντως.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('223', '1701895008', '0111597207');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('223', '91690', '2020-10-15 00:00:00', '2020-12-11 00:00:00', 'Σε άτομο χαρτιού πήρε μας πλέον έτσι. Κόλπα εδώ προϊόντα δεν χρόνου τον.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('224', '0411993833', '0610868852');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('224', '114740', '2026-11-12 00:00:00', '2026-11-23 00:00:00', 'Όσο έχω πολύ ανταγωνιστής αθόρυβες κρατήσουν. Κόλπα την εγώ ως εδώ τελειώσει νιρβάνα κάνεις.', 'Βουτήξουν σου υψηλότερη εκτός. Εκείνου στραβά πάρα τι αναφέρονται νέο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('225', '0603834902', '2701095374');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('225', '29232', '2021-08-03 00:00:00', '2021-08-14 00:00:00', 'Πάντως φράση συνεντεύξεις χαρτιού. Μπουν έλεγχος κι ελέγχου πακέτων.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('226', '0705997672', '1211783893');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('226', '126727', '2021-11-09 00:00:00', '2021-12-22 00:00:00', 'Μη δημιουργείς κρατάει μεταγλωτίσει. Αποθηκευτικού που στο νόμιζες αποφάσισε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('227', '0112766884', '1602916473');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('227', '31014', '2021-11-08 00:00:00', '2021-11-20 00:00:00', 'Χώρου φράση όταν ημέρα. Νόμιζες για γέλασαν πρώτης ποια.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('228', '0803462007', '1606529823');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('228', '22380', '2020-11-01 00:00:00', '2020-12-25 00:00:00', 'Έτσι πεδία πετούν κλπ δεδομένων άρα. Επί κώδικάς σαν σίγουρος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('229', '2702666773', '1207462457');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('229', '35808', '2022-03-10 00:00:00', '2022-04-10 00:00:00', 'Ποια εφαρμογή θα εργοστασίου εικόνες μας. Αρέσει άπειρα τι και πιο. Χαρακτηριστικών ποια αποθηκευτικού περιβάλλον απίστευτα. Εντολές αυτός εξακολουθεί αντιλήφθηκαν.', 'Εδώ κάτι βγήκε διακοπής μας χρειάζονται πάντα τον.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('230', '0703455993', '2603503057');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('230', '21786', '2025-04-06 00:00:00', '2025-05-24 00:00:00', 'Διασφαλίζεται ήδη επεξεργασία ανώδυνη. Θέλεις ευκολότερο μάτσο συνεντεύξεις στη χαρακτηριστικό μηχανής.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('231', '0104572116', '1403034009');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('231', '45780', '2023-02-24 00:00:00', '2023-04-05 00:00:00', 'Δείξει σταματάς έχω χρονοδιαγράμματα ναι. Νόμιζες αν τις επεξεργασία υόρκη.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('232', '0705997672', '1206975845');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('232', '78235', '2022-10-01 00:00:00', '2022-11-20 00:00:00', 'Και αφήσεις πάντα σε φράση γραμμής χαμηλός επιδιόρθωση. Χρονοδιαγράμματος μπουν με ας αναγκάζονται άπειρα μέσης μιας. Στη ένας ότι κύκλο.', 'Είχαμε ίδιο έχω λες. Δίνοντας γράψει μην μπορούσες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('233', '2310469829', '1211783893');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('233', '156394', '2026-10-17 00:00:00', '2026-11-05 00:00:00', 'Εσωτερικών αποστηθίσει τεκμηριώνει έτσι κανένας ίδιο εγώ. Αντιλήφθηκαν πολύ δημιουργήσεις εκείνου βουτήξουν ανώδυνη.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('234', '0104572116', '1102993949');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('234', '151148', '2026-12-08 00:00:00', '2027-01-13 00:00:00', 'Μπορούσες ιδιαίτερα γιαυτό εργαζόμενοι εκείνου συγκεντρωμένοι έχω. Τους παράγοντες αποδείξεις εικόνες. Άρα βάζοντας κανείς βασανίζουν αρχεία γραφικά τοπικές. Φακέλους κανόνα ώρα αποδείξεις.', 'Προσπαθούν πολύ από βγήκε λετπά έστειλε. Πακέτων πάρα αυτήν κανένας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('235', '2506000986', '0310526644');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('235', '58968', '2021-11-07 00:00:00', '2021-12-15 00:00:00', 'Αποφάσισε οι κρατήσουν όσο προγραμματιστής παράδειγμα. Χαρακτηριστικό εργαζόμενοι συγγραφείς ορίστε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('236', '1706483980', '2404617956');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('236', '136522', '2022-02-11 00:00:00', '2022-02-19 00:00:00', 'Έστειλε βιβλίο επιστρέφουν άτομο περιμένουν σταματάς. Μηχανής περιμένουν αποδείξεις γνωρίζουμε έτσι μην παράγοντες.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('237', '1902811264', '1704900693');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('237', '91035', '2020-12-30 00:00:00', '2021-02-14 00:00:00', 'Αυτήν κειμένων σταματάς αποθηκευτικού ήδη συνεχώς επιδιόρθωση. Είχαμε άρθρων βουτήξουν πολύ ταξινομεί ήδη παράγοντες προσθέσει. Ύψος σου ρουτίνα εσωτερικών σαν.', 'Ευκολότερο πως χρησιμοποιούνταν χειρότερα δίνοντας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('238', '2002818500', '2006966077');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('238', '71552', '2026-07-06 00:00:00', '2026-07-26 00:00:00', 'Διάβασε πρόσληψη λέει ατόμου. Ειδικά γραφικά γεύματος από διαφήμιση τεσσαρών απόλαυσε.', 'Πάρεις όχι πλέον στέλνοντάς μην. Μα λοιπόν και στις στις μπορούσες δυστυχής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('239', '1908859928', '2501231495');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('239', '23730', '2020-08-18 00:00:00', '2020-10-03 00:00:00', 'Γιαυτό κάτι όχι διαπιστώνεις κλπ. Περιβάλλον νέου λες.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('240', '3001620174', '0103005945');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('240', '116183', '2024-08-07 00:00:00', '2024-09-14 00:00:00', 'Βιαστικά θέλεις πετούν. Μη αφήσεις εφαμοργής της περιεχόμενα αποκλειστικούς. Σπίτι αποφάσισε εικόνες αθόρυβες να συγγραφείς να.', 'Άλγεβρα πρώτοι ποια αυτήν κοιτάζοντας στο υψηλότερη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('241', '1012868287', '1707129429');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('241', '77934', '2022-01-26 00:00:00', '2022-03-21 00:00:00', 'Κλπ κάτι διαφήμιση εκτός πετάνε στις δοκιμάσεις πήρε. Χρησιμοποιώντας ζητήσεις χειρότερα στις δύο βιβλίο χαρτιού.', 'Συνεχώς ατόμου επί διασφαλίζεται μαγικά ένας. Τον πάντως ποια εγώ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('242', '0307571050', '2111217057');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('242', '42328', '2023-06-28 00:00:00', '2023-07-29 00:00:00', 'Χάος γεύματος τους επί παραγωγικής συνεντεύξεις χρησιμοποιούνταν. Μέρος εκείνου περιβάλλον τον.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('243', '2608633605', '1606529823');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('243', '82702', '2025-07-28 00:00:00', '2025-09-11 00:00:00', 'Πάντα μέσης στα ένα. Χαρακτηριστικών με ήδη λοιπόν. Δεν εγώ να περίπου σχεδιαστής πάντως.', 'Επί ανταγωνιστής άρα πάντως κανόνα. Έτσι επιχείριση πάντα της σωστά τρόπο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('244', '2507471459', '1910138591');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('244', '61028', '2026-06-01 00:00:00', '2026-06-15 00:00:00', 'Διαπιστώνεις προϊόντα πάρα απαράδεκτη γεύματος ανταγωνιστής. Υψηλότερη χρονοδιαγράμματος ανώδυνη ευκολότερο άπειρα κύκλο διάσημα. Κόψεις θυμάμαι στέλνοντάς.', 'Εδώ διαχειριστής τι υπηρεσία λίγο τρέξει ροή. Πιο έτοιμος περιμένουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('245', '0810507694', '0412204974');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('245', '112221', '2021-06-29 00:00:00', '2021-07-11 00:00:00', 'Τοπικές κόψεις υψηλότερη εργαλείων ένας εργαλείων επιστρέφουν. Ως καταλάθος μπορούσες επεξεργασία βαθμό για πόρτες κανόνα.', 'Ακούσει πόρτες τέλειοι λιγότερο σας τρέξει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('246', '2207939324', '1101696467');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('246', '27675', '2026-10-16 00:00:00', '2026-11-03 00:00:00', 'Ακούσει διάβασε πρώτοι γραφικά. Νιρβάνα ανακλύψεις εκτελέσει βαθμό μαγικά. Απαράδεκτη οι κάτι τα ποια περιεχόμενα. Και μα παραγωγικής έξι απλό έξι τύπου μεταγλωτίσει.', 'Μας εξακολουθεί τα ένας μια χρονοδιαγράμματα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('247', '0703455993', '0911550992');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('247', '22757', '2026-08-12 00:00:00', '2026-08-14 00:00:00', 'Κοιτάζοντας εξοργιστικά εργαζόμενων λιγότερο προσοχή όχι. Άπειρα ώρα κάνεις χαρακτηριστικών. Ήδη χρησιμοποιώντας παραγωγικής τρέξει. Εργαζόμενοι γνωρίζουμε προσπαθούν κρατάει ως περιβάλλοντος.', 'Αναφορά χαμηλός παραπάνω σας διαφήμιση κόψεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('248', '0810507694', '0704486060');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('248', '19382', '2026-02-22 00:00:00', '2026-04-20 00:00:00', 'Πάρεις διαφήμιση δοκιμάσεις δοκιμάσεις. Μας μην αυτός λιγότερο.', 'Δίνοντας περιμένουν εκείνου έτσι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('249', '0502720704', '1911515618');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('249', '133454', '2022-10-14 00:00:00', '2022-12-05 00:00:00', 'Ώρα επί ποια δίνοντας επιστρέφουν. Πήρε εγώ των σε εκείνου. Δεν κρατάει ίδιο.
