INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('251', '0705997672', '0609732815');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('251', '11742', '2022-02-03 00:00:00', '2022-03-13 00:00:00', 'Πάντως επιδιόρθωση τη νιρβάνα. Μέρος επί όταν υψηλότερη ωραίο γιαυτό.', 'Χρησιμοποίησέ καταλάθος έτσι κάτι συνεχώς μας. Σαν ροή όχι δύο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('252', '0208916047', '2506405612');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('252', '124115', '2022-05-24 00:00:00', '2022-05-29 00:00:00', 'Εγώ βιβλίο είχαμε συνάδελφος παραδοτέου μάλλον. Τους ναι ερωτήσεις λέει αυτός μάλλον έξι.', 'Ότι φακέλους τι αποστηθίσει. Σε αρέσει εδώ ήδη ώρα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('253', '1812640874', '1207710361');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('253', '48649', '2024-08-25 00:00:00', '2024-09-25 00:00:00', 'Ο κώδικα σου έχω στήλες μετράει εκτελέσει. Με λετπά χειρότερα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('254', '2711519870', '1602916473');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('254', '37332', '2020-02-02 00:00:00', '2020-03-20 00:00:00', 'Ίδιο δωροδοκηθούν γραμμές διακοπής δύο βάζοντας από. Τις ναι ευκολότερο βάζοντας διαφήμιση δούλευε ανεπιθύμητη.
