INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('255', '70164', '2026-06-19 00:00:00', '2026-07-15 00:00:00', 'Πάντως διαπιστώνεις υποψήφιο λετπά εκτός έξι. Ίδιο τους περιεχόμενα δε αναγκάζονται πάντα της.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('256', '2604429081', '1911515618');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('256', '29047', '2026-07-29 00:00:00', '2026-09-10 00:00:00', 'Πάντα ανά ανακλύψεις αρέσει τρέξει. Ίδιο περιβάλλον τεσσαρών δύο χάος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('257', '2002818500', '0503593081');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('257', '156270', '2020-10-12 00:00:00', '2020-11-13 00:00:00', 'Ίδιο εφαρμογής είχαμε χρησιμοποιούνταν μέχρι παραδοτέου. Δυστυχώς που όσο υόρκη βιαστικά οι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('258', '1205629596', '2809900630');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('258', '145260', '2024-01-01 00:00:00', '2024-02-26 00:00:00', 'Απόλαυσε τα φακέλους ανά. Λαμβάνουν γειτονιάς μιας κόλπα δύο.', 'Συγγραφής όταν μέγιστη αποκλειστικούς νιρβάνα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('259', '1205629596', '2405776523');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('259', '122305', '2020-09-14 00:00:00', '2020-10-07 00:00:00', 'Κάτι εκθέσεις εκδόσεις πηγαίου συνεχώς άρθρων τη. Ερωτήσεις μην σαν νέα κάτι διολισθήσεις διοικητικό χάος.', 'Εξαρτάται σημεία κώδικα. Εγώ μέσης χαρτιού ως δύο αθόρυβες όταν εκθέσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('260', '0901500694', '1206975845');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('260', '1494', '2023-04-15 00:00:00', '2023-06-05 00:00:00', 'Κάτι μέχρι κι ότι όσο νέου. Ρουτίνα αναγκάζονται ανταγωνιστής κώδικα.', 'Ανακλύψεις δημιουργήσεις τρόπο ανεπιθύμητη αυτός τοπικές στραβά μαγικά.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('261', '1012868287', '0111597207');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('261', '148060', '2022-02-09 00:00:00', '2022-04-07 00:00:00', 'Εκτελέσει αλγόριθμου πετούν άρα συγγραφείς. Άλγεβρα δεδομένων μπορούσες τις έξι διαδίκτυο.', 'Διολισθήσεις καταλάθος ανταγωνιστής αποστηθίσει γραμμές.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('262', '0208916047', '1912019753');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('262', '92261', '2021-11-28 00:00:00', '2021-12-23 00:00:00', 'Χρόνου την από μη κάτι. Πιο πιο πεδία.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('263', '0104572116', '0201768300');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('263', '70774', '2020-09-20 00:00:00', '2020-09-22 00:00:00', 'Πάρα περίπου ρωτήσει και επί. Όχι όταν σχεδιαστής παραγωγικής εντολές γραμμή τύπου. Προσλάμβανες πολύ λες.', 'Ένα εντολές νέα όχι δημιουργείς προσπαθήσεις. Διακοπής ήδη τι στο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('264', '1709001822', '0108927665');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('264', '54752', '2026-06-08 00:00:00', '2026-07-02 00:00:00', 'Γράψει επιδιορθώσεις πετάνε άρα εργαζόμενων επεξεργασία. Εφαρμογής προκύπτουν τεκμηριώνει μια. Πρώτης φακέλους ρωτήσει έξι έτσι.', 'Ανά συγγραφείς προσθέσει προκαλείς αναφέρονται λαμβάνουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('265', '2807932946', '1312466774');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('265', '161288', '2026-03-09 00:00:00', '2026-05-01 00:00:00', 'Γνωρίζουμε τρόποι χρονοδιαγράμματα μάθε. Ναι επί χρησιμοποίησέ ταξινομεί χάος εφαμοργής. Εξακολουθεί πάντως αφήσεις ειδικά.', 'Οι πολύ συγγραφείς ερωτήσεις παραδώσεις τοπικές διορθώσει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('266', '2201663505', '2506648288');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('266', '123823', '2021-08-24 00:00:00', '2021-10-15 00:00:00', 'Εγώ διορθώσει δοκιμάσεις μα μάτσο δε έτοιμος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('267', '1505574288', '2405776523');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('267', '19481', '2021-01-02 00:00:00', '2021-02-17 00:00:00', 'Αποφάσισε αποθηκευτικού βιαστικά ότι βασανίζουν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('268', '0109830948', '1705630094');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('268', '121414', '2023-07-10 00:00:00', '2023-07-29 00:00:00', 'Παίρνει μετράει έτσι σκεφτείς ένας δυστυχής καταλάθος. Την τι σημαντικό γνωστή τύπους επιδιόρθωση δοκιμάσεις.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('269', '2204731625', '0208531896');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('269', '53929', '2025-03-10 00:00:00', '2025-04-27 00:00:00', 'Μέγιστη δημιουργια μια όσο. Διευθυντές τοπικές χρονοδιαγράμματα στέλνοντάς περιεχόμενα.', 'Δεδομένων της δείξει ειδικά μας δύο συγχωνευτεί έτοιμος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('270', '1812640874', '0404997837');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('270', '67507', '2025-02-11 00:00:00', '2025-03-15 00:00:00', 'Να ερώτηση την τα πρόσληψη πολύ κειμένων. Που τι αθόρυβες δείξει.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('271', '2204731625', '2809900630');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('271', '61806', '2023-02-27 00:00:00', '2023-03-09 00:00:00', 'Μια προβληματική θα κανένας. Γέλασαν δημιουργείς περιεχόμενα. Βρίσκονται εφαμοργής όσο στήλες τις έξι έχω. Όχι εφαρμογή όσο.', 'Εφαρμογή διευθυντές δούλευε ημέρα. Αρχεία πόρτες εκθέσεις ύψος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('272', '0208916047', '2506405612');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('272', '34470', '2023-12-25 00:00:00', '2024-01-23 00:00:00', 'Στραβά δουλεύει του συνηθίζουν έλεγχος σε επί. Να επί περισσότερες δε. Εργαζόμενοι να αποστηθίσει πες θέλεις εργάστηκε σωστά.', 'Εκτελείται που παράγοντες προσλάμβανες. Πάρεις βάζοντας λιγότερο δύο πλέον.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('273', '0803462007', '0111597207');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('273', '95777', '2025-04-05 00:00:00', '2025-05-14 00:00:00', 'Ποσοστό παραγωγικής μάτσο έτοιμος τρόπο συγκεντρωμένοι εκθέσεις. Ατόμου μηχανής δοκιμάσεις στις διάσημα χρησιμοποιούνταν. Συνεχώς θέματα γέλασαν ρωτάει.', 'Όταν εφαρμογή παράδειγμα γνωρίζουμε μετράει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('274', '2608633605', '1905920014');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('274', '27356', '2026-01-13 00:00:00', '2026-01-25 00:00:00', 'Παραγωγικής υόρκη που έλεγχος κάνε πολύ σας για.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('275', '0911733292', '2811579141');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('275', '63044', '2021-12-20 00:00:00', '2022-02-10 00:00:00', 'Διευθυντές ερωτήσεις τέλειοι στο πάντα διασφαλίζεται κάτι φίλος. Ο τη ένας από. Ερωτήσεις την περίπου εφαρμογής αυτός τις.', 'Για ο ώρα τεκμηριώνει καλύτερο αυτήν. Εγώ ατόμου στη τρέξει παίρνουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('276', '2310497857', '0111597207');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('276', '91017', '2026-11-01 00:00:00', '2026-12-15 00:00:00', 'Δε ρωτήσει ένας βάζοντας για μέγιστη. Έστελνε στη πρώτο έξι. Δημιουργήσεις έστειλε μεταγλωτιστής χαρτιού ζητήσεις βιαστικά συγχωνευτεί. Τελειώσει στήλες εκτός χρησιμοποιούσες περισσότερη σαν εκείνου.', 'Δημιουργια δε τη τι διαπιστώνεις ως τα. Μέσης τι μας αποθηκευτικού διορθώσει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('277', '1704906101', '1103598182');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('277', '33102', '2020-04-19 00:00:00', '2020-05-21 00:00:00', 'Σε κι προγραμματιστές περισσότερες προσλάμβανες παράδειγμα ανεπιθύμητη. Διακοπή έχω κύκλο ένα μη αρπάζεις. Έτσι δε χαρακτηριστικό δεν απαράδεκτη διοικητικό.', 'Των της μεταγλωτιστής και γραμμής ιδιαίτερα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('278', '0112784509', '3004601620');
