INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('279', '1701895008', '3007896243');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('279', '126031', '2020-08-28 00:00:00', '2020-09-29 00:00:00', 'Δε πετάξαμε δημιουργείς την λιγότερο παραπάνω. Πολύ έχω καταλάθος αυτός πάντως.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('280', '0810507694', '2611597541');
